window.BOOK = {"meta":{"title":"C++ 완전 정복","subtitle":"언어 코어부터 ROS 2 로봇 제어까지","std":"C++20"},"toc":[{"id":"start","num":"Part 0","title":"시작하기","desc":"이 책의 사용법과 실습 환경. 컴파일러·CMake·디버거를 세우고, 직접 타이핑하는 학습 원칙과 듀얼 모니터 워크플로를 잡는다.","chapters":[{"num":"0.1","id":"how-to-read","title":"이 책을 읽는 법","desc":"목적별 읽기 경로, 표기 규칙, 위젯 조작법, 학습 원칙"},{"num":"0.2","id":"toolchain-setup","title":"컴파일러, CMake, 디버거 설치","desc":"g++/clang, gdb, CMake, ROS 2 Humble Docker 실습 환경"},{"num":"0.3","id":"first-build","title":"첫 빌드와 에러 메시지 읽는 법","desc":"컴파일러가 뱉는 텍스트를 정보로 바꾸는 훈련"},{"num":"0.4","id":"workflow","title":"학습 워크플로: 앱과 IDE의 병행","desc":"듀얼 모니터 배치, 복습 루틴, 폰 EPUB 활용"}]},{"id":"core","num":"Part I","title":"C++ 코어","desc":"컴파일 모델부터 타입 시스템, 함수, 헤더와 링크리지까지. C++ 프로그램이 소스에서 실행파일이 되는 전 과정을 이해한다.","chapters":[{"num":"1.1","id":"compile-model","title":"컴파일 모델: 전처리 → 컴파일 → 링크","desc":"번역 단위, 오브젝트 파일, 링커 에러의 정체"},{"num":"1.2","id":"types","title":"타입 시스템: 정수, 부동소수점, 문자","desc":"고정폭 정수, 오버플로, 부동소수점의 실체"},{"num":"1.3","id":"variables","title":"변수, 초기화, 스코프","desc":"초기화 문법의 지뢰밭, 스코프와 수명의 구분"},{"num":"1.4","id":"casting","title":"캐스팅과 타입 변환","desc":"암묵 변환의 함정, static_cast부터 reinterpret_cast까지"},{"num":"1.5","id":"control-flow","title":"제어 흐름과 표현식","desc":"평가 순서, 단락 평가, switch의 fallthrough"},{"num":"1.6","id":"functions","title":"함수: 오버로딩과 인자 전달","desc":"값/참조 전달의 비용, 오버로드 해석, 기본 인자"},{"num":"1.7","id":"arrays-strings","title":"배열과 문자열","desc":"C 배열의 붕괴(decay), std::string의 내부, 리터럴"},{"num":"1.8","id":"structs-enums","title":"구조체와 열거형","desc":"집성체 초기화, enum class, 패딩 미리보기"},{"num":"1.9","id":"headers","title":"헤더와 컴파일 단위","desc":"#include의 실체, 헤더 가드, 선언과 정의의 분리"},{"num":"1.10","id":"linkage","title":"네임스페이스와 링크리지","desc":"ODR, static/extern/inline, 이름 충돌의 해부"}]},{"id":"memory","num":"Part II","title":"메모리와 소유권","desc":"이 책의 심장. 스택과 힙, 포인터, RAII, 이동 시맨틱, 스마트 포인터 — C++을 C++답게 만드는 소유권 모델을 위젯과 함께 몸에 새긴다.","chapters":[{"num":"2.1","id":"memory-model","title":"메모리 모델: 스택, 힙, 정적 영역","desc":"함수 호출 스택의 동작, 힙 할당의 실체"},{"num":"2.2","id":"pointers","title":"포인터: 주소를 값으로 다룬다","desc":"*, &, 포인터 산술, nullptr — 화살표로 이해한다"},{"num":"2.3","id":"references","title":"레퍼런스: 별명의 규칙","desc":"포인터와의 차이, 왜 재바인딩이 없는가, const&"},{"num":"2.4","id":"dynamic-alloc","title":"new/delete와 동적 할당의 비용","desc":"할당자가 하는 일, 누수와 이중 해제, 왜 직접 쓰지 않는가"},{"num":"2.5","id":"raii","title":"RAII: 소멸자가 자원을 관리한다","desc":"C++에서 가장 중요한 관용구, 예외 안전성의 기초"},{"num":"2.6","id":"copy-semantics","title":"복사 시맨틱","desc":"복사 생성자, 복사 대입, 얕은 복사가 만드는 버그"},{"num":"2.7","id":"move-semantics","title":"이동 시맨틱과 rvalue 레퍼런스","desc":"std::move의 실체, moved-from 상태, 값 범주"},{"num":"2.8","id":"rule-of-five","title":"Rule of 0/3/5","desc":"특수 멤버 함수의 생성 규칙, =default와 =delete"},{"num":"2.9","id":"unique-ptr","title":"unique_ptr: 독점 소유권","desc":"제로 비용 소유권, 커스텀 딜리터, 팩토리 패턴"},{"num":"2.10","id":"shared-ptr","title":"shared_ptr와 weak_ptr","desc":"참조 카운트의 실제 비용, 순환 참조, 제어 블록"},{"num":"2.11","id":"ub-sanitizers","title":"댕글링, UB, 새니타이저","desc":"미정의 동작의 정체, ASan/UBSan으로 잡는 법"},{"num":"2.12","id":"object-layout","title":"객체 메모리 레이아웃과 정렬","desc":"sizeof의 비밀, 패딩, alignas, 캐시 라인 미리보기"}]},{"id":"oop","num":"Part III","title":"객체지향과 다형성","desc":"클래스 설계부터 vtable의 실체까지. 가상함수 호출이 실제로 어떤 포인터를 따라가는지 위젯으로 확인한다.","chapters":[{"num":"3.1","id":"classes","title":"클래스: 캡슐화와 불변식","desc":"public/private의 진짜 목적, 멤버 초기화 리스트"},{"num":"3.2","id":"constructors","title":"생성자와 소멸자의 모든 것","desc":"생성 순서, 위임 생성자, explicit, 소멸 순서"},{"num":"3.3","id":"inheritance","title":"상속: is-a의 비용","desc":"객체 슬라이싱, protected의 함정, 다중 상속"},{"num":"3.4","id":"virtual-vtable","title":"가상함수와 vtable","desc":"동적 디스패치의 실제 구조, 가상 소멸자, final/override"},{"num":"3.5","id":"abstract-interfaces","title":"추상 클래스와 인터페이스 설계","desc":"순수 가상함수, NVI 패턴, 플러그인 구조의 뼈대"},{"num":"3.6","id":"operator-overloading","title":"연산자 오버로딩","desc":"언제 쓰고 언제 참는가, 삼중 비교 <=>, 관용구"},{"num":"3.7","id":"composition","title":"컴포지션 vs 상속","desc":"결합도의 관점에서 다시 보는 설계 선택"},{"num":"3.8","id":"class-design","title":"클래스 설계 실전","desc":"const 정확성, 인터페이스 최소화, 로봇 도메인 예제"}]},{"id":"generic","num":"Part IV","title":"제네릭 프로그래밍","desc":"템플릿은 코드를 찍어내는 컴파일 타임 기계다. 인스턴스화 과정을 위젯으로 보고, concepts로 제약을 걸고, constexpr로 컴파일 타임에 계산한다.","chapters":[{"num":"4.1","id":"function-templates","title":"함수 템플릿","desc":"타입 추론, 인스턴스화, 왜 헤더에 써야 하는가"},{"num":"4.2","id":"class-templates","title":"클래스 템플릿과 특수화","desc":"전체/부분 특수화, 템플릿 파라미터의 종류"},{"num":"4.3","id":"template-mechanics","title":"템플릿 인스턴스화의 실체","desc":"코드 팽창, 링크, 에러 메시지 해독법"},{"num":"4.4","id":"variadic-templates","title":"가변 인자 템플릿과 폴드 표현식","desc":"파라미터 팩, 재귀 없는 전개, 실전 패턴"},{"num":"4.5","id":"concepts","title":"Concepts (C++20)","desc":"제약을 타입에 새긴다, requires, 에러 메시지의 혁명"},{"num":"4.6","id":"constexpr","title":"constexpr와 컴파일 타임 계산","desc":"constexpr/consteval, 룩업 테이블을 컴파일 타임에"},{"num":"4.7","id":"type-deduction","title":"auto, decltype, 타입 추론 규칙","desc":"추론이 벗겨내는 것, auto&&, 함정 모음"}]},{"id":"stl","num":"Part V","title":"STL 완전정복","desc":"컨테이너별 내부 구조와 실제 비용, 반복자, 알고리즘, 람다. 어떤 자료구조를 왜 고르는지가 이 파트의 전부다.","chapters":[{"num":"5.1","id":"vector","title":"vector: 내부 구조와 성장 전략","desc":"capacity의 실체, 재할당과 무효화, reserve"},{"num":"5.2","id":"assoc-containers","title":"map, set, unordered_map","desc":"레드블랙 트리 vs 해시 테이블, 실측 비용 비교"},{"num":"5.3","id":"seq-containers","title":"deque, list, array","desc":"언제 vector가 아닌가 — 거의 없다는 것의 증명"},{"num":"5.4","id":"iterators","title":"반복자와 무효화 규칙","desc":"반복자 카테고리, 범위 기반 for의 실체, 무효화 표"},{"num":"5.5","id":"algorithms","title":"<algorithm> 완전 정복","desc":"sort/find/transform, erase-remove, ranges(C++20)"},{"num":"5.6","id":"lambdas","title":"람다와 클로저","desc":"캡처의 실체 — 컴파일러가 만드는 클래스, 캡처 함정"},{"num":"5.7","id":"callables","title":"std::function과 콜러블","desc":"타입 소거의 비용, 함수 포인터와의 선택 기준"},{"num":"5.8","id":"views","title":"string_view와 span","desc":"소유하지 않는 뷰, 수명 함정, API 설계에의 적용"},{"num":"5.9","id":"vocabulary-types","title":"optional, variant, expected","desc":"값으로 표현하는 부재·선택·실패"}]},{"id":"concurrency","num":"Part VI","title":"동시성과 실시간","desc":"스레드, 락, atomic, 그리고 실시간 제약. 데이터 레이스가 실제로 발생하는 인터리빙을 위젯으로 재생하며 이해한다. 로봇 제어 루프 설계의 기반.","chapters":[{"num":"6.1","id":"threads","title":"std::thread: 생성, join, 수명","desc":"스레드의 비용, jthread, 왜 detach를 피하는가"},{"num":"6.2","id":"data-races","title":"데이터 레이스의 해부","desc":"인터리빙, 왜 ++이 원자적이 아닌가, UB로서의 레이스"},{"num":"6.3","id":"mutex","title":"mutex와 락 가드","desc":"lock_guard/unique_lock/scoped_lock, 데드락 회피"},{"num":"6.4","id":"condvar","title":"condition_variable과 대기 패턴","desc":"스퓨리어스 웨이크업, 생산자-소비자 큐 구현"},{"num":"6.5","id":"atomic","title":"atomic과 메모리 오더","desc":"가시성과 순서, seq_cst부터 relaxed까지 실측"},{"num":"6.6","id":"lockfree","title":"lock-free 기초와 SPSC 큐","desc":"CAS, ABA 문제, 실시간 통신용 링 버퍼"},{"num":"6.7","id":"async-future","title":"async, future, promise","desc":"태스크 기반 병렬성, async의 함정, 패키지드 태스크"},{"num":"6.8","id":"realtime","title":"실시간 제약과 제어 루프","desc":"왜 제어 루프에서 malloc·락을 피하나, 지터, 우선순위"},{"num":"6.9","id":"thread-architecture","title":"스레드 아키텍처 설계","desc":"hardware_interface의 스레드 분리 구조를 처음부터 설계한다"}]},{"id":"build-quality","num":"Part VII","title":"빌드·툴체인·품질","desc":"CMake, gdb, 새니타이저, GoogleTest, clang-tidy. 도구를 직접 IDE 터미널에서 굴리며 프로덕션급 개발 사이클을 만든다.","chapters":[{"num":"7.1","id":"cmake-basics","title":"CMake 기초: 타겟과 프로퍼티","desc":"타겟 중심 사고, PUBLIC/PRIVATE/INTERFACE"},{"num":"7.2","id":"cmake-advanced","title":"CMake 심화","desc":"find_package, FetchContent, 설치와 export"},{"num":"7.3","id":"package-managers","title":"vcpkg와 Conan","desc":"의존성 관리의 현실, ROS 생태계와의 관계"},{"num":"7.4","id":"gdb","title":"gdb로 디버깅하기","desc":"중단점, 워치포인트, 코어 덤프, VSCode 연동"},{"num":"7.5","id":"sanitizers","title":"ASan, UBSan, TSan","desc":"메모리 버그를 컴파일 플래그 하나로 잡는다"},{"num":"7.6","id":"googletest","title":"GoogleTest로 테스트 작성","desc":"픽스처, 파라미터화, 모킹의 기초"},{"num":"7.7","id":"static-analysis","title":"clang-tidy와 정적 분석","desc":"코드 냄새를 커밋 전에 잡는다, .clang-tidy 설정"},{"num":"7.8","id":"ci","title":"CI 파이프라인 구성","desc":"GitHub Actions로 빌드·테스트·새니타이저 자동화"}]},{"id":"performance","num":"Part VIII","title":"성능 엔지니어링","desc":"측정 없이 최적화 없다. 프로파일링, 캐시와 메모리 레이아웃, 컴파일러가 실제로 만드는 코드 읽기, SIMD 기초.","chapters":[{"num":"8.1","id":"profiling","title":"프로파일링: perf와 측정 방법론","desc":"어디가 느린지 추측하지 않고 측정한다"},{"num":"8.2","id":"cache","title":"캐시와 메모리 레이아웃","desc":"캐시 미스의 실제 비용, AoS vs SoA, false sharing"},{"num":"8.3","id":"codegen","title":"컴파일러 최적화와 코드 생성","desc":"Compiler Explorer로 어셈블리 읽기, 최적화 레벨"},{"num":"8.4","id":"data-oriented","title":"데이터 지향 설계","desc":"객체 지향이 캐시를 죽이는 지점, 로봇 상태 배열 설계"},{"num":"8.5","id":"simd","title":"SIMD 기초","desc":"자동 벡터화를 돕는 코드, intrinsics 맛보기"},{"num":"8.6","id":"benchmarking","title":"마이크로벤치마크의 함정","desc":"Google Benchmark, 죽은 코드 제거와 싸우기"}]},{"id":"robomath","num":"Part IX","title":"로보틱스 수학","desc":"Eigen 선형대수, 회전과 좌표 변환, 순·역기구학, 칼만 필터, PID. 헥사포드 다리 IK와 leg odometry로 직결되는 수학을 C++로 구현한다.","chapters":[{"num":"9.1","id":"eigen","title":"Eigen: 선형대수를 C++로","desc":"Matrix/Vector 타입, 표현식 템플릿, 성능 함정"},{"num":"9.2","id":"rotations","title":"회전 표현: 행렬, 오일러, 쿼터니언","desc":"짐벌락, 쿼터니언 연산, 어느 표현을 언제 쓰나"},{"num":"9.3","id":"transforms","title":"동차 변환과 좌표 프레임","desc":"4×4 변환 행렬, 프레임 체인, TF 트리의 수학"},{"num":"9.4","id":"forward-kinematics","title":"순기구학","desc":"관절 각도에서 발끝 위치까지, DH 파라미터"},{"num":"9.5","id":"inverse-kinematics","title":"역기구학","desc":"해석해와 수치해, 헥사포드 3자유도 다리 IK 구현"},{"num":"9.6","id":"state-estimation","title":"상태 추정: 칼만 필터에서 EKF까지","desc":"불확실성의 수학, 센서 융합의 뼈대"},{"num":"9.7","id":"pid","title":"PID 제어 기초","desc":"P·I·D 각 항의 역할, 튜닝, 안티 와인드업"},{"num":"9.8","id":"numerics","title":"수치 안정성과 부동소수점 함정","desc":"누적 오차, 특이점 근처의 동작, epsilon 비교"}]},{"id":"ros2","num":"Part X","title":"ROS 2 with C++ (rclcpp)","desc":"노드, 토픽, 서비스, 액션부터 executor, QoS, tf2, ros2_control까지. rclcpp를 라이브러리 사용법이 아니라 아키텍처로 이해한다.","chapters":[{"num":"10.1","id":"rclcpp-node","title":"rclcpp: 노드의 해부학","desc":"노드 생명주기, 컨텍스트, spin의 실체"},{"num":"10.2","id":"pub-sub","title":"토픽: publisher와 subscription","desc":"메시지 흐름, 직렬화, intra-process 통신"},{"num":"10.3","id":"services-actions","title":"서비스와 액션","desc":"요청-응답, 장기 실행 목표, 어느 통신을 언제 쓰나"},{"num":"10.4","id":"executors","title":"executor와 callback group","desc":"콜백이 실제로 실행되는 스레드, 블로킹의 전파"},{"num":"10.5","id":"qos","title":"QoS 완전 이해","desc":"reliability/durability/history, 안 맞으면 조용히 끊긴다"},{"num":"10.6","id":"params-launch","title":"파라미터와 launch","desc":"선언적 파라미터, launch 파일, 컴포저블 노드"},{"num":"10.7","id":"tf2","title":"tf2로 좌표 변환 다루기","desc":"TF 트리, lookupTransform, 시간과 보간"},{"num":"10.8","id":"lifecycle","title":"lifecycle 노드","desc":"관리되는 상태 전이, 왜 로봇 시스템에 필요한가"},{"num":"10.9","id":"ros2-control","title":"ros2_control과 hardware_interface","desc":"컨트롤러 매니저, 하드웨어 추상화, 실시간 루프"},{"num":"10.10","id":"ament-colcon","title":"ament, colcon, 패키지 구조","desc":"ROS 2 빌드 시스템의 실체, CMake와의 관계"}]},{"id":"robostack","num":"Part XI","title":"로봇 SW 스택","desc":"Nav2 플러그인, MoveIt2, OpenCV, PCL, Gazebo. 실제 로봇 SW 스택의 C++ 확장 지점을 직접 구현한다.","chapters":[{"num":"11.1","id":"pluginlib","title":"pluginlib와 플러그인 아키텍처","desc":"동적 로딩의 실체, 클래스 로더, 플러그인 작성 절차"},{"num":"11.2","id":"nav2-costmap","title":"Nav2 costmap layer 플러그인","desc":"costmap 구조, 커스텀 레이어 구현"},{"num":"11.3","id":"nav2-controller","title":"Nav2 controller/planner 플러그인","desc":"경로 추종 컨트롤러를 직접 만든다"},{"num":"11.4","id":"moveit2","title":"MoveIt2 C++ API","desc":"모션 플래닝 파이프라인, planning scene, move group"},{"num":"11.5","id":"opencv","title":"OpenCV C++ 핵심","desc":"cv::Mat의 메모리 모델, 카메라 파이프라인"},{"num":"11.6","id":"pcl","title":"PCL로 포인트클라우드 다루기","desc":"포인트 타입 템플릿, 필터링, 정합"},{"num":"11.7","id":"gazebo","title":"Gazebo 연동과 시뮬레이션","desc":"월드/모델, ros_gz, 센서 시뮬레이션"}]},{"id":"portfolio","num":"Part XII","title":"실전·포트폴리오","desc":"프로덕션 코드 리딩, 코드 리뷰 관점, 기술면접 C++ 개념 질문 총정리, 그리고 Hexpider 프로젝트와의 매핑.","chapters":[{"num":"12.1","id":"reading-ros2-control","title":"프로덕션 코드 리딩: ros2_control","desc":"실제 소스에서 이 책의 개념을 전부 찾아낸다"},{"num":"12.2","id":"reading-nav2","title":"프로덕션 코드 리딩: Nav2","desc":"대규모 C++ 코드베이스를 읽는 전략"},{"num":"12.3","id":"code-review","title":"코드 리뷰 관점: 로봇 C++ 체크리스트","desc":"리뷰어의 눈으로 자기 코드를 본다"},{"num":"12.4","id":"interview-cpp","title":"기술면접 C++ 개념 질문 총정리","desc":"메모리·동시성·설계 — 전 파트 interview 상자의 집대성"},{"num":"12.5","id":"hexpider-map","title":"Hexpider 로드맵 매핑","desc":"이 책의 각 파트가 헥사포드의 어느 단계에 쓰이는가"}]}],"docs":{"how-to-read":"# 0.1 이 책을 읽는 법\n\n::: lead\n이 책의 목표는 하나다. **ROS 2를 C++만으로 자유롭게 구현하는 로봇 애플리케이션 개발자**가 되는 것. 이 절은 그 목표까지 가는 지도이자 사용 설명서다. 10분이면 읽는다. 건너뛰지 마라 — 특히 이 책의 두 기둥인 **위젯 조작법**과 **타이핑 원칙**이 여기 있다. 이 책을 어떻게 쓰느냐가 도달 지점을 결정한다.\n:::\n\n## 이 책이 서 있는 자리\n\n시중의 C++ 자료는 대개 세 종류다.\n\n| 종류 | 다루는 것 | 빠진 것 |\n| --- | --- | --- |\n| 입문서 | 문법, 클래스, 간단한 예제 | 메모리에서 실제로 무슨 일이 일어나는지 |\n| 심화서 (Effective 시리즈 등) | 관용구, 함정, 모범 사례 | 처음 배우는 사람을 위한 발판, 응용 분야 |\n| 분야별 전문서 (ROS 2 등) | 해당 프레임워크 API | 언어의 기반, 왜 그 API가 그렇게 생겼는지 |\n\n셋을 다 사서 읽으면 될 것 같지만, 실제로는 잘 안 된다. **연결이 끊기기 때문**이다. 입문서의 포인터가 왜 `rclcpp`의 `SharedPtr` 콜백 시그니처로 이어지는지, 심화서의 이동 시맨틱이 왜 메시지 파이프라인의 제로 카피와 닿아 있는지, executor가 왜 스레드와 락의 문제인지 — 이런 질문의 답은 세 책 **사이**에 있다.\n\n이 책은 그 사이를 메우려고 쓴다. 그래서 순서가 이렇다.\n\n::: note 이 책의 논리 구조\n**언어의 골격**(Part I)을 세우면 → **메모리와 소유권**(Part II)이 C++의 심장임을 알게 되고 → **다형성·템플릿·STL**(Part III~V)이 그 위의 표현 도구로 보이고 → **동시성**(Part VI)으로 로봇 제어 루프의 전제를 갖추고 → **도구와 성능**(Part VII~VIII)으로 프로덕션급 개발 사이클을 만들고 → **로보틱스 수학**(Part IX)을 C++로 구현한 뒤 → **ROS 2**(Part X)와 **로봇 SW 스택**(Part XI)이 이 모두를 로봇 위에서 조립하고 → **실전·포트폴리오**(Part XII)로 마무리한다.\n:::\n\n## 지금 당신의 위치\n\n이 책은 **일반 프로그래밍 경험이 있는 사람**을 기준으로 쓴다. 변수, 함수, 조건문, 반복문이 무엇인지 알고, 어떤 언어로든 프로그램을 짜 본 적이 있으면 충분하다. C++ 특유의 것 — 포인터, 수동 메모리 관리, 템플릿, RAII — 는 모른다고 가정하고 바닥부터 다룬다.\n\n그렇다고 Part I을 건너뛰지 마라. Part I은 \"변수 선언하는 법\"을 가르치지 않는다. **소스 파일이 실행파일이 되기까지 컴파일러와 링커가 실제로 무엇을 하는지**를 다룬다. 아래 코드가 왜 이런 결과를 내는지 3초 안에 설명할 수 있다면 1.1절을 훑고 넘어가도 좋다. 못 하겠다면, 거기가 당신의 출발점이다.\n\n```cpp title=\"이 코드는 컴파일될까?\"\n#include <iostream>\n\nint add(int a, int b);          // 선언만 있고 정의가 없다\n\nint main() {\n    std::cout << add(1, 2) << \"\\n\";\n    return 0;\n}\n```\n\n::: answer 답이 궁금하다면\n**컴파일은 통과하고, 링크에서 실패한다.** `add`의 선언이 있으므로 컴파일러는 호출 코드를 만들 수 있다. 하지만 링커가 `add`의 실제 몸체를 찾지 못해 `undefined reference to 'add(int, int)'` 를 뱉는다. \"컴파일 에러\"와 \"링커 에러\"는 완전히 다른 단계에서 나는 완전히 다른 에러다 — 이 구분이 [1.1 컴파일 모델](#/compile-model)의 주제이고, ROS 2에서 라이브러리 링크가 꼬였을 때 당신을 구해줄 지식이다.\n:::\n\n## 이 책의 표기 규칙\n\n읽는 데 필요한 약속들이다.\n\n### 인터랙티브 위젯 — 이 책의 핵심 도구\n\n공간적인 개념(스택/힙, 포인터, 소유권, 스레드 인터리빙)은 글 대신 **조작 가능한 위젯**으로 보여준다. 아래가 위젯이다. 지금 직접 만져 보라.\n\n::: widget demo\n{ \"values\": [3, 1, 4, 1, 5, 9, 2, 6], \"title\": \"위젯 조작 연습\" }\n:::\n\n모든 위젯의 조작법은 같다.\n\n- **다음 ▶ / ◀ 이전** — 한 스텝씩 진행·되감기. 위젯의 기본 사용법이다.\n- **▶ 재생** — 자동으로 스텝을 넘긴다. 한 번 흐름을 본 뒤에는 수동 스텝을 권한다.\n- **슬라이더** — 아무 스텝으로나 점프.\n- 위젯 아래 **설명 줄**이 지금 스텝에서 일어난 일을 말해 준다. 그림과 설명을 같이 읽어라.\n\n위젯은 눈요기가 아니다. **스텝을 앞뒤로 오가며 \"왜 이 상태가 됐는가\"를 스스로 설명할 수 있을 때** 그 개념이 당신 것이 된다. 뒤에서 만날 스택/힙 위젯, 포인터 위젯, 스레드 타임라인 위젯이 전부 이 방식이다.\n\n### 코드 블록\n\n컴파일 가능한 완결된 코드는 이렇게 나온다. 오른쪽 위 **복사** 버튼이 있지만, 잠시 뒤 설명할 이유로 **누르지 않기를 권한다.**\n\n```cpp title=\"greet.cpp\"\n#include <iostream>\n#include <string>\n\nstd::string greet(const std::string& name) {\n    return \"hello, \" + name;\n}\n\nint main() {\n    std::cout << greet(\"hexpider\") << \"\\n\";\n    return 0;\n}\n```\n\n터미널 세션은 이렇게 표시한다. **`$` 로 시작하는 줄이 명령**이고, 나머지는 실제 출력이다.\n\n```console\n$ g++ -std=c++20 -Wall -Wextra greet.cpp -o greet\n$ ./greet\nhello, hexpider\n```\n\n주목해야 할 줄은 강조해 둔다. 아래에서는 4번 줄이 핵심이다.\n\n```cpp title=\"함정: 댕글링 레퍼런스\" {4}\nconst std::string& make_name() {\n    std::string local = \"temp\";\n    return local;               // 지역변수의 레퍼런스를 반환한다\n}                               // local 은 여기서 파괴된다 — 반환된 레퍼런스는 시체를 가리킨다\n```\n\n이 책의 코드는 전부 **C++20, `-Wall -Wextra` 에서 경고 없이 컴파일되는 것**을 기준으로 한다. 조각 코드는 조각임을 밝힌다.\n\n### 표시 상자\n\n본문 흐름을 끊지 않으면서 따로 봐야 할 것들은 상자에 담는다.\n\n::: note 노트\n알아두면 좋은 보충 설명. 몰라도 진도는 나가지만 알면 이해가 깊어진다.\n:::\n\n::: tip 팁\n실무에서 통하는 요령. 대개 \"이렇게 하면 편하다\" 류.\n:::\n\n::: warn 주의\n틀리기 쉬운 지점. 여기서 한 번은 반드시 삽질한다.\n:::\n\n::: danger 함정\n**버그를 만드는** 지점. C++은 함정의 언어라 이 상자가 자주 나온다. 실제 장애·크래시·UB로 이어지는 것만 여기 넣는다.\n:::\n\n::: deep 깊이 보기\n컴파일러 내부, 표준 문서, ABI 같은 한 단계 아래 이야기. 처음 읽을 때는 건너뛰어도 된다. 두 번째 읽을 때 여기가 재미있어진다면 실력이 붙은 것이다.\n:::\n\n::: perf 성능\n실행 속도·메모리에 직접 영향을 주는 사실. 반드시 측정 결과가 붙는다.\n:::\n\n::: interview 기술면접 포인트\n실제 기술면접에서 이 개념이 어떻게 질문되는지 + 모범 답변의 뼈대. **이 상자만 모아 읽으면 C++ 면접 대비 속성 코스**가 된다. Part XII의 [12.4 기술면접 총정리](#/interview-cpp)가 이 상자들의 집대성이다.\n:::\n\n::: hist 배경\n왜 이렇게 설계됐는지에 대한 역사. C++의 이상한 구석은 대부분 C 호환성과 제로 오버헤드 원칙에서 나왔다 — 맥락을 알면 잘 안 잊힌다.\n:::\n\n::: quiz 연습문제\n직접 풀어 보는 문제. 답을 보기 전에 최소 3분은 손으로 써 보길 권한다. Part II부터는 **당신의 컴퓨터에서 컴파일이 통과해야 성공**인 문제가 섞인다.\n:::\n\n### 용어\n\n기술 용어는 **한국어 + 영어 병기**로 처음 나올 때 한 번 표기한다. 예: 미정의 동작(undefined behavior, UB), 자원 획득은 초기화(RAII). 이후에는 문맥에 따라 편한 쪽을 쓴다. 영어 문서·컴파일러 에러 메시지를 읽어야 하는 분야이므로 원어를 지우지 않는다. 왼쪽 아래 **용어 사전**에서 모든 용어의 최초 정의 위치를 찾을 수 있다.\n\n## 어떻게 읽을 것인가\n\n### 원칙 1 — 손으로 치지 않은 코드는 읽지 않은 것이다\n\n이 앱에는 코드 실행 기능이 없다. **일부러 뺐다.** 실행은 당신의 실제 IDE와 컴파일러에서 한다 — 이것이 이 책의 학습 방식 그 자체다.\n\n이유는 단순하다. C++에서 타이핑 실수는 낭비가 아니라 훈련이다. 세미콜론을 빠뜨리고, 헤더를 안 붙이고, `const`를 빼먹을 때마다 컴파일러가 에러 메시지를 뱉는다. **그 메시지를 읽고 고치는 반복이 C++ 실력의 절반이다.** 복사-붙여넣기는 그 훈련 기회를 전부 버린다. [0.3 첫 빌드와 에러 메시지 읽는 법](#/first-build)에서 이 훈련을 본격적으로 시작한다.\n\n특히 **결과를 예측한 뒤에 실행하라.** \"이건 링커 에러가 날 거야\" 하고 엔터를 친다. 맞으면 지식이 확인되고, 틀리면 그 순간이 가장 크게 배우는 순간이다.\n\n### 원칙 2 — 듀얼 모니터: 한쪽에 이 앱, 한쪽에 IDE\n\n이 앱은 PC 전용이고, **모니터 두 대(또는 화면 분할)를 전제로 설계했다.** 한쪽에 이 앱을, 다른 쪽에 IDE(VSCode + 터미널)를 띄운다. 절을 읽다가 코드가 나오면 그 자리에서 IDE로 쳐 보고, 위젯으로 이해를 확인하고, 다시 본문으로 돌아온다. 창을 절반 폭으로 줄여도 레이아웃이 깨지지 않게 만들어져 있다.\n\n이동 중 복습은 이 앱이 아니라 **EPUB 파일**로 한다 — 같은 본문에서 위젯만 뺀 순수 텍스트 버전을 폰 기본 e리더로 여는 방식이다. [0.4 학습 워크플로](#/workflow)에서 설정법을 다룬다.\n\n### 원칙 3 — 막히면 표시하고 넘어간다\n\nPart II의 이동 시맨틱이나 Part VI의 메모리 오더 같은 주제는 처음에 안 와닿는 게 정상이다. 각 절 맨 아래 **'이 절을 완료로 표시'** 버튼이 있고, 왼쪽 목차에 체크(✓)가 남는다. 완벽히 이해한 절만 체크하고, 나머지는 비워 둔 채 진도를 나가라. 뒤쪽을 읽다 보면 앞쪽이 저절로 풀리는 일이 매우 흔하다 — vtable을 배우면 가상 소멸자가, executor를 배우면 콜백 그룹이 풀린다.\n\n::: tip 검색을 적극적으로 써라\n상단 돋보기 또는 <kbd>/</kbd> 키로 **전체 본문 검색**이 열린다. \"vtable\", \"RAII\", \"QoS\" 처럼 개념 이름으로 찾으면 그 개념을 다루는 모든 절이 나온다. 이 책은 앞에서 뒤로 읽는 것만큼이나 **필요할 때 찾아 읽는 레퍼런스**로 쓰라고 만들었다.\n:::\n\n### 원칙 4 — 목적에 맞는 경로를 탄다\n\n전체를 순서대로 읽는 게 이상적이지만, 급한 목표가 있다면 아래 경로를 쓴다.\n\n**기술 면접이 코앞이라면**\n\n1. 전 파트의 🎤 **기술면접 포인트** 상자만 훑는다\n2. [12.4 기술면접 C++ 개념 질문 총정리](#/interview-cpp)로 마무리\n3. 시간이 남으면 Part II 전체 — 면접 C++ 질문의 절반은 메모리와 소유권이다\n\n**헥사포드(Hexpider) 실전이 급하다면**\n\n1. Part II 전체 — `ros2_control`도 결국 소유권과 수명 문제다\n2. Part IV 4.1~4.3 (템플릿) — Eigen과 PCL을 읽으려면 필요하다\n3. Part VI (동시성) — 제어 루프와 통신 스레드의 분리가 전부 여기 있다\n4. Part IX (로보틱스 수학) → Part X (ROS 2)\n\n**언어만 빠르게 한 바퀴 돌고 싶다면**\n\nPart I → II → III 순서로 읽되, 각 절의 `deep` 상자는 건너뛴다. 두 바퀴째에 `deep`만 다시 읽는다.\n\n::: warn 지름길의 대가\n경로를 타면 빨리 도달하지만, 반드시 **되돌아와서 메운다**. Part II를 건너뛰고 Part X로 간 사람은 콜백에 잡힌 `SharedPtr`가 왜 메모리를 안 놓는지, 왜 노드가 소멸돼도 타이머가 도는지 앞에서 멈춘다. API 사용법은 검색으로 해결되지만 **왜 그런지**는 검색으로 안 나온다. 그 차이가 이 책의 존재 이유다.\n:::\n\n## 실습 환경\n\nPart 0의 나머지 절에서 환경을 제대로 세운다. 지금은 결론만 알아 두자.\n\n- **C++20** 기준으로 쓴다. C++17 이하와 갈리는 지점은 그때마다 표시한다.\n- 컴파일러는 **g++ 13 이상** 또는 **clang 16 이상**. 리눅스(우분투) 기준으로 설명하고, 다른 OS는 [0.2 설치](#/toolchain-setup)에서 다룬다.\n- 빌드는 **CMake**, 디버깅은 **gdb**, 메모리 검증은 **ASan/UBSan**. 전부 [Part VII](#/cmake-basics)에서 깊게 다루지만 설치는 0.2에서 미리 한다.\n- **Part X(ROS 2)** 는 ROS 2 Humble 기준이다. 우분투 + Docker 환경 구성을 0.2에서 안내한다.\n\n## 이 앱 자체에 대해\n\n이 책은 **HTML 파일 하나와 마크다운 묶음**으로 되어 있다. 서버도, 인터넷도, 빌드 도구도 필요 없다. `index.html`을 더블클릭하면 열린다.\n\n- **왼쪽 목차**: 부(Part)를 접었다 펼 수 있고, 위쪽 칸에서 목차를 걸러낼 수 있다. 완료한 절에는 ✓ 가 붙는다.\n- **오른쪽 목차**: 지금 보는 절 안에서의 위치. 화면이 좁으면 숨는다.\n- **진도**: 왼쪽 위 원형 그래프. 브라우저 `localStorage`에 저장된다 — 이 PC의 이 브라우저가 진도의 기준점이다.\n- **용어 사전**: 왼쪽 아래. 모든 용어의 한 줄 정의와 최초 등장 챕터.\n- **테마·글자 크기**: 상단 오른쪽 아이콘.\n- **단축키**: <kbd>/</kbd> 또는 <kbd>Ctrl</kbd>+<kbd>K</kbd> 검색, <kbd>[</kbd> 이전 절, <kbd>]</kbd> 다음 절, <kbd>Esc</kbd> 닫기.\n\n## 시작하기 전에\n\n마지막으로 하나만.\n\n이 책은 길다. 100개가 넘는 절이 있고, 전부 읽으면 웬만한 전공 서적 몇 권 분량이다. **끝까지 읽는 것이 목표가 아니다.** 목표는 *\"모르는 것이 나왔을 때 어디를 봐야 할지 아는 상태\"*, 그리고 *\"세그폴트가 나도 당황하지 않고 한 층 아래로 내려가서 확인할 수 있다는 자신감\"* 이다.\n\nC++은 추상화의 뚜껑을 열 수 있는 언어다. 뚜껑을 열면 스택 프레임이 보이고, vtable이 보이고, 캐시 라인이 보인다. 이 책은 그 \"한 층 아래\"를 매번 위젯과 함께 같이 내려가 주는 책이다.\n\n그럼 시작하자.\n\n---\n\n## 요약\n\n- 이 책의 목표는 **ROS 2를 C++로 자유롭게 다루는 로봇 개발자**다. Part I~VIII이 언어, Part IX~XII가 로보틱스 도메인이다.\n- 공간적 개념은 **위젯**으로 배운다. 스텝을 앞뒤로 오가며 상태 변화를 스스로 설명할 수 있어야 한다.\n- **코드는 복사하지 말고 직접 쳐라.** 컴파일 에러를 읽는 것이 훈련의 절반이다.\n- 듀얼 모니터: 한쪽에 이 앱, 한쪽에 IDE. 이동 중 복습은 EPUB.\n- 막히면 표시하고 넘어가라. 뒤를 읽으면 앞이 풀린다.\n- 급하면 목적별 경로(면접/Hexpider/언어 일주)를 타되, 반드시 되돌아와 메워라.\n\n::: quiz 워밍업\n읽고 넘어가기 전에, 아래 세 가지를 스스로 답해 보자. 지금 못 해도 괜찮다. **Part I~II를 마친 뒤 다시 와서 답해 보라** — 그게 이 책이 작동했는지 확인하는 가장 좋은 방법이다.\n\n1. `std::string a = \"x\"; std::string b = a;` 에서 힙 할당은 몇 번 일어나는가? `b = std::move(a);` 라면?\n2. 컴파일 에러와 링커 에러는 각각 어느 단계에서, 왜 나는가? `undefined reference` 는 어느 쪽인가?\n3. 스레드 두 개가 같은 `int` 변수에 `++` 를 한 번씩 하면 결과는 항상 2 증가인가? 아니라면 왜인가?\n:::\n\n**다음 절**: [0.2 컴파일러, CMake, 디버거 설치](#/toolchain-setup) — 도구를 제대로 깔고 실습 환경을 세운다.\n","toolchain-setup":"# 0.2 컴파일러, CMake, 디버거 설치\n\n::: lead\n이 절에서 이 책 전체를 지탱할 도구를 설치한다 — 컴파일러(g++), 빌드 시스템(CMake), 디버거(gdb), 그리고 편집기(VSCode). 설치 자체는 명령 몇 줄이면 끝난다. 중요한 것은 그다음이다: **깔린 도구가 진짜로 C++20을 컴파일하는지, CMake가 빌드를 만들어내는지, gdb가 프로그램 속을 들여다보는지**를 직접 확인한다. 여기서 확인한 명령들이 앞으로 수백 번 반복될 당신의 기본 동작이 된다. 마지막에는 Part X를 위한 ROS 2 Humble Docker 환경까지 잡는다.\n:::\n\n## 무엇을 깔고, 왜 이 조합인가\n\n설치할 것은 네 가지다.\n\n| 도구 | 역할 | 이 책에서 깊게 다루는 곳 |\n| --- | --- | --- |\n| **g++** (GCC의 C++ 컴파일러) | 소스를 실행파일로 | [1.1 컴파일 모델](#/compile-model) |\n| **gdb** | 실행 중인 프로그램의 내부 관찰 | [7.4 gdb로 디버깅하기](#/gdb) |\n| **CMake** | 빌드 절차의 기술과 자동화 | [7.1 CMake 기초](#/cmake-basics) |\n| **VSCode** | 편집기 + 위 셋의 조종석 | [0.4 학습 워크플로](#/workflow) |\n\n넷의 관계는 이렇다. 컴파일 명령을 만들어 주는 것이 CMake, 그 명령을 실제로 수행하는 것이 g++, 그 결과물을 열어 보는 것이 gdb다. VSCode는 셋을 한 화면에서 부리는 자리다.\n\n```text nolines\n main.cpp ---> [ g++ ] ---> app ---> [ gdb ]\n                  ^\n                  | build commands\n              [ CMake ] <--- CMakeLists.txt\n```\n\n왜 clang이나 MSVC가 아니라 g++인가. 취향 문제가 아니라 **목적지가 정해 준 선택**이다. 이 책의 종착점인 ROS 2는 우분투를 1순위 플랫폼으로 삼고, 공식 바이너리가 GCC로 빌드되며, ROS 2의 빌드 도구인 colcon과 ament도 결국 내부에서 CMake와 GCC를 부른다([10.10 ament, colcon, 패키지 구조](#/ament-colcon)에서 이 관계를 해부한다). 지금 우분투에서 g++와 CMake에 손을 붙여 두면, Part X에서 만나는 ROS 2 빌드 시스템은 이미 아는 것의 포장일 뿐이다. clang은 뒤에서 정적 분석 도구(clang-tidy)로 합류하고, macOS 사용자의 주 컴파일러이기도 하다 — 아래 \"다른 OS\" 절에서 다룬다.\n\n## 우분투에서 설치하기\n\n이 책의 기준 환경은 **우분투 24.04 LTS**다. 설치는 세 패키지로 끝난다.\n\n```console\n$ sudo apt update\n$ sudo apt install build-essential gdb cmake\n```\n\n::: note build-essential의 내용물\n`build-essential`은 단일 프로그램이 아니라 메타패키지다. 안에 gcc, **g++**, make, 그리고 C 표준 라이브러리 헤더(libc6-dev)가 들어 있다. C++ 컴파일러만 필요해도 이 묶음으로 까는 이유가 있다 — 링크 단계에서 C 런타임과 시스템 헤더가 반드시 필요하고, 그게 빠진 환경에서 나는 에러는 초심자가 해석하기 가장 어려운 종류이기 때문이다.\n:::\n\n설치가 끝나면 세 도구의 버전을 확인한다. 이 확인 습관은 요식이 아니다 — 컴파일러 버전은 지원하는 C++ 표준과 에러 메시지의 생김새를 결정하고, 남에게 질문할 때 가장 먼저 밝혀야 할 정보다.\n\n```console\n$ g++ --version\ng++ (Ubuntu 13.3.0-6ubuntu2~24.04.1) 13.3.0\n$ gdb --version\nGNU gdb (Ubuntu 15.1-1ubuntu1~24.04.1) 15.1\n$ cmake --version\ncmake version 3.28.3\n```\n\n(Ubuntu 24.04 / g++ 13 기준 실측. 배포판에 따라 버전은 다르다.)\n\n이 책의 최소선은 [0.1](#/how-to-read)에서 말한 대로 **g++ 13 이상**이다. g++ 13은 이 책이 쓰는 C++20 기능을 전부 지원한다.\n\n::: warn 우분투 22.04를 쓰고 있다면\n22.04의 기본 g++는 11이고, C++20 지원에 구멍이 있다. 세 가지 길이 있다: (1) 24.04로 올린다 — 가장 깔끔하다. (2) 아래 Docker 절의 방식으로 컨테이너 안에서 작업한다. (3) 별도 저장소에서 새 g++를 받는다 — 시스템 기본 컴파일러가 둘이 되는 상태를 스스로 관리할 수 있을 때만 권한다. 어느 쪽이든 `g++ --version`으로 13 이상을 확인하고 넘어가라.\n:::\n\n## C++20이 진짜 도는지 확인\n\n버전 숫자를 봤다고 끝이 아니다. **C++20 코드를 실제로 컴파일해 본다.** 아래 코드는 C++20에서 새로 들어온 두 기능을 쓴다 — 멤버 이름을 지정하는 초기화(designated initializer)와, 템플릿 인자에 제약을 거는 콘셉트(concepts). 둘 다 뒤에서 제대로 배우니 지금은 \"C++20에만 있는 문법\"이라는 사실만 알면 된다.\n\n```cpp title=\"check20.cpp\"\n#include <concepts>\n#include <iostream>\n\nstruct JointState {\n    double position;\n    double velocity;\n    double effort;\n};\n\n// C++20 concepts: 부동소수점 타입만 받는 함수\ntemplate <std::floating_point T>\nT half(T v) { return v / 2; }\n\nint main() {\n    // C++20 designated initializer\n    JointState js{ .position = 1.57, .velocity = 0.0, .effort = 3.2 };\n    std::cout << \"pos=\" << js.position << \" half=\" << half(js.effort) << \"\\n\";\n    return 0;\n}\n```\n\n`JointState`라는 이름이 낯설다면 기억해 둘 가치가 있다 — 관절 하나의 위치·속도·토크를 담는 이 세 필드 구조는 ROS 2의 관절 상태 메시지, 그리고 ros2_control이 하드웨어와 주고받는 인터페이스의 최소 단위와 같은 모양이다. 이 책의 예제는 이렇게 처음부터 로봇의 어휘로 쓴다.\n\n컴파일하고 실행한다. `-std=c++20`이 핵심이다.\n\n```console\n$ g++ -std=c++20 -Wall -Wextra check20.cpp -o check20\n$ ./check20\npos=1.57 half=1.6\n```\n\n(Ubuntu 24.04 / g++ 13.3 기준 실측.)\n\n이 두 줄이 나왔다면 당신의 컴파일러는 이 책의 모든 코드를 받아들일 준비가 됐다.\n\n::: warn -std=c++20은 항상 직접 붙여야 한다\ng++ 13의 기본 표준은 C++20이 아니라 **C++17**(정확히는 GNU 확장이 섞인 gnu++17)이다. 플래그 없이 `g++ check20.cpp`만 치면 아래에서 볼 C++17 에러가 그대로 난다. \"최신 컴파일러를 깔았으니 최신 표준이겠지\"는 성립하지 않는다 — 기본값은 기존 코드의 호환성을 위해 보수적으로 잡혀 있다. CMake 프로젝트에서 이 플래그를 강제하는 방법은 [7.1](#/cmake-basics)에서 다룬다.\n:::\n\n### 일부러 틀려 보기: -std=c++17로 컴파일하면\n\n같은 파일을 C++17로 컴파일하면 무슨 일이 생기는지 보자. 이 대비가 \"표준 버전\"이라는 개념을 몸에 새긴다.\n\n```console\n$ g++ -std=c++17 -Wall -Wextra check20.cpp -o check17\ncheck20.cpp:11:11: error: 'std::floating_point' has not been declared\n   11 | template <std::floating_point T>\n      |           ^~~\ncheck20.cpp:12:1: error: 'T' does not name a type\n   12 | T half(T v) { return v / 2; }\n      | ^\ncheck20.cpp: In function 'int main()':\ncheck20.cpp:17:55: error: 'half' was not declared in this scope\n   17 |     std::cout << \"pos=\" << js.position << \" half=\" << half(js.effort) << \"\\n\";\n      |                                                       ^~~~\n```\n\n(g++ 13.3 기준 실측. 에러 메시지의 문구는 컴파일러 버전에 따라 다르다.)\n\n읽는 법을 다음 절에서 훈련하겠지만, 지금도 구조는 보인다 — 첫 에러가 원인(`std::floating_point`는 C++17에 없다)이고, 나머지 둘은 그 여파다. 첫 에러부터 고치는 것이 철칙이다.\n\n::: warn 조용히 통과하는 쪽이 더 위험하다\n눈여겨볼 것: 에러 세 개가 전부 concepts에서 났고, **designated initializer에 대한 에러는 없다.** g++는 이 문법을 C++17 모드에서도 GNU 확장으로 조용히 받아 준다. `-Wpedantic`을 붙여야 실측으로 이런 경고가 나온다: `warning: C++ designated initializers only available with '-std=c++20' [-Wc++20-extensions]`. \"내 컴퓨터에서 컴파일됐다\"와 \"표준 C++이다\"는 다른 명제다 — 다른 컴파일러, 다른 팀, 다른 CI로 코드가 이동하는 순간 이 차이가 청구서가 되어 돌아온다.\n:::\n\n## CMake와 gdb 스모크 테스트\n\n컴파일러가 확인됐으니 나머지 둘도 실전 형태로 한 번씩 굴려 본다. 문법 공부가 아니라 **설치 검증**이다 — 각 도구의 내용은 Part VII에서 제대로 다룬다.\n\n먼저 CMake. 새 디렉터리에 두 파일을 만든다.\n\n```cmake title=\"CMakeLists.txt\"\ncmake_minimum_required(VERSION 3.16)\nproject(hello CXX)\nset(CMAKE_CXX_STANDARD 20)\nset(CMAKE_CXX_STANDARD_REQUIRED ON)\nadd_executable(hello main.cpp)\n```\n\n```cpp title=\"main.cpp\"\n#include <iostream>\nint main() { std::cout << \"toolchain ok\\n\"; }\n```\n\nCMake의 사용은 두 단계다. **구성(configure)** — 컴파일러를 찾고 빌드 파일을 생성한다. **빌드(build)** — 생성된 빌드 파일로 실제 컴파일을 수행한다.\n\n```console\n$ cmake -B build -S .\n-- Detecting CXX compile features - done\n-- Configuring done (0.2s)\n-- Generating done (0.0s)\n-- Build files have been written to: .../hello/build\n$ cmake --build build\n[ 50%] Building CXX object CMakeFiles/hello.dir/main.cpp.o\n[100%] Linking CXX executable hello\n[100%] Built target hello\n$ ./build/hello\ntoolchain ok\n```\n\n(cmake 3.28 / g++ 13 기준 실측. 구성 출력은 앞부분을 생략했다.)\n\n빌드 출력의 두 줄에 주목하라 — `Building`(컴파일)과 `Linking`(링크)이 **별개의 단계**로 나온다. 이 구분이 [1.1 컴파일 모델](#/compile-model)의 주제이고, C++ 에러의 절반을 가르는 선이다.\n\n다음은 gdb. 디버거로 열 프로그램은 `-g` 플래그로 컴파일해야 한다 — 실행파일 안에 소스 줄 번호와 변수 이름을 담는 옵션이다. 아까의 check20.cpp를 다시 쓴다.\n\n```console\n$ g++ -std=c++20 -g check20.cpp -o check20\n$ gdb -q ./check20\n(gdb) break main\nBreakpoint 1 at 0x1176: file check20.cpp, line 16.\n(gdb) run\nBreakpoint 1, main () at check20.cpp:16\n16\t    JointState js{ .position = 1.57, .velocity = 0.0, .effort = 3.2 };\n(gdb) print js\n$1 = {position = 7.8726316228683315e-85, velocity = 2.1165311283480734e+214, effort = 6.9533558072160389e-310}\n(gdb) quit\n```\n\n(gdb 15.1 기준 실측. `print js`의 값은 실행할 때마다 다르다.)\n\n`break main`으로 중단점을 걸고 `run`으로 실행하면, 프로그램이 16번 줄 **직전에** 멈춘다. 그 상태에서 `print js`가 보여 주는 값을 보라 — `position`이 1.57이 아니라 `7.87e-85` 같은 난수다. 초기화 줄이 **아직 실행되지 않았기 때문에**, `js`가 차지한 스택 메모리에 이전부터 굴러다니던 쓰레기 비트가 그대로 읽힌 것이다. C++는 초기화하지 않은 변수를 0으로 만들어 주지 않는다. 이 사실이 만드는 버그의 전모는 Part II에서 다루지만, 디버거는 첫날부터 이렇게 언어의 맨살을 보여 준다.\n\n::: tip 새니타이저까지 한 번에 확인\n이 책의 실습 명령에는 `-fsanitize=address`가 자주 붙는다. 메모리 버그를 실행 시점에 잡아 주는 ASan이라는 도구인데([7.5](#/sanitizers)), 별도 설치가 필요 없다 — g++가 이미 품고 있다. `g++ -std=c++20 -g -fsanitize=address check20.cpp -o check20 && ./check20`이 정상 실행되면 그 확인도 끝난 것이다.\n:::\n\n## VSCode 세팅\n\n편집기는 **VSCode + Microsoft의 C/C++ 확장(ms-vscode.cpptools)** 을 기준으로 한다. VSCode는 공식 사이트에서 우분투용 .deb 패키지를 받아 설치하고, 확장은 확장 탭에서 \"C/C++\"를 검색해 설치한다. 이 조합을 기준으로 삼는 이유는 하나다 — 코드 완성부터 gdb 연동 디버깅([7.4](#/gdb)에서 씀)까지 확장 하나로 끝나서, 도구 배관에 쓰는 시간이 가장 적다.\n\n::: note clangd를 이미 쓰고 있다면\n코드 완성 엔진으로 clangd를 선호하는 사람도 많고, 대형 코드베이스에서는 더 빠르기도 하다. 그대로 써도 이 책 진행에 아무 지장이 없다 — 이 책이 VSCode에 기대는 것은 \"편집 + 터미널 + 디버거가 한 화면\"이라는 배치뿐이고, 그 배치는 [0.4 학습 워크플로](#/workflow)에서 잡는다.\n:::\n\n단, 한 가지 원칙. **컴파일은 처음 몇 주간 IDE 버튼이 아니라 터미널에서 직접 명령으로 하라.** `g++ -std=c++20 -Wall -Wextra main.cpp` 를 손으로 치는 동안 플래그 하나하나가 의미로 남는다. 버튼 뒤에 숨은 빌드는 [1.1](#/compile-model)을 지난 뒤에 써도 늦지 않다.\n\n## 다른 OS에서는\n\n**Windows** — WSL2에 우분투 24.04를 깔고 그 안에서 위의 우분투 절차를 그대로 따르는 것을 권한다. 이유는 두 가지다. 첫째, ROS 2 실습(Part X)까지 같은 리눅스 환경을 유지할 수 있어 도구가 두 벌이 되지 않는다. 둘째, MSVC는 에러 메시지도 플래그 체계도 GCC와 달라서, 이 책의 실측 출력과 당신의 화면이 계속 어긋난다. VSCode는 WSL 확장으로 WSL2 안의 코드를 네이티브처럼 편집한다.\n\n**macOS** — Xcode Command Line Tools의 `g++`는 이름만 g++고 실체는 Apple clang이다. 문제는 버전 표기다: Apple clang의 버전 번호는 LLVM 본가의 번호와 **다른 체계**라, \"clang 16 이상\"이라는 이 책의 기준과 직접 비교할 수 없고, C++20 지원에 빈 구석이 있는 버전이 흔하다. Homebrew로 LLVM 본가(`brew install llvm`)나 GCC(`brew install gcc`)를 설치하고 버전을 확인한 뒤 쓰라. 이 책의 리눅스 실측 출력과 세부가 다를 수 있다는 점은 감안해야 한다.\n\n두 경우 모두 이 책은 출력을 싣지 않는다 — 리눅스 실측만 싣는 것이 이 책의 원칙이고, 당신 화면의 출력이 곧 당신 환경의 진실이다.\n\n## ROS 2 Humble 실습 환경 — Docker\n\n마지막 조각이다. Part X부터 쓰는 ROS 2 Humble은 **우분투 22.04를 기준 플랫폼으로 배포**되므로, 지금 세운 24.04 호스트에 그대로 설치할 수 없다. Docker가 이 판을 깔끔하게 정리한다 — 22.04 + ROS 2가 통째로 들어 있는 이미지를 컨테이너로 띄우면, 호스트에는 아무것도 설치하지 않고 격리된 실습 환경을 얻는다. 로봇 현장에서도 이 방식이 표준에 가깝다: 배포 대상 로봇과 개발 PC의 OS가 다른 상황이 기본값이라, ROS 2 개발 환경은 컨테이너로 고정해 두는 팀이 많다.\n\nDocker 자체는 배포판 문서에 따라 설치했다고 가정하고, ROS 2 이미지를 받는 명령은 이렇다.\n\n```console\n$ docker pull osrf/ros:humble-desktop\n```\n\n::: note 이미지 태그 고르기\n`ros:humble`은 통신·빌드 핵심만 담은 공식 슬림 이미지고, `osrf/ros:humble-desktop`은 거기에 RViz 같은 시각화 도구까지 얹은 것이다. 이 책의 실습에는 desktop을 권한다 — 용량을 아끼려다 Part X에서 도구가 없어 다시 받는 일이 흔하다.\n:::\n\n컨테이너를 띄울 때는 작업 디렉터리를 호스트와 공유해 두는 것이 요령이다. 컨테이너 안에서 편집한 코드가 호스트에도 남는다.\n\n```console\n$ mkdir -p ~/ros2_ws\n$ docker run -it --name ros2 -v ~/ros2_ws:/ros2_ws osrf/ros:humble-desktop\n```\n\n`-v 호스트경로:컨테이너경로`가 그 공유 옵션이다. 셸이 뜨면 `ros2 --help`가 동작하는지 확인해 보라.\n\n::: tip 컨테이너는 지워져도 되는 존재로 다뤄라\n`-v`로 공유한 디렉터리에만 작업물을 두면, 컨테이너는 언제든 지우고(`docker rm ros2`) 새로 띄울 수 있는 소모품이 된다. \"환경이 꼬이면 갈아엎는다\"가 Docker를 쓰는 이유의 절반이다 — 컨테이너 안에서만 존재하는 파일에 애착을 갖는 순간 그 장점이 사라진다.\n:::\n\n지금은 이미지를 받아 셸이 뜨는 것까지만 확인하면 된다. GUI 연결, 워크스페이스 구성, colcon 빌드는 Part X 진입 시점에 [10.10 ament, colcon, 패키지 구조](#/ament-colcon)와 함께 단계적으로 세운다.\n\n## 요약\n\n- 이 책의 도구 사슬은 **g++ 13+ / gdb / CMake / VSCode**, 기준 OS는 우분투 24.04다. 이 조합은 ROS 2 생태계의 표준 경로와 일치한다 — colcon/ament도 결국 CMake와 GCC를 부른다.\n- 설치는 `sudo apt install build-essential gdb cmake` 한 줄, 검증은 `--version` 세 번이다. 버전은 지원 표준과 에러 메시지를 결정하는 핵심 정보다.\n- g++ 13의 기본 표준은 C++17이다. **모든 컴파일에 `-std=c++20`을 직접 붙인다.**\n- \"컴파일된다\"와 \"표준 C++이다\"는 다르다 — GNU 확장은 조용히 통과한다. `-Wall -Wextra`를 습관으로 붙이고, 이식성이 걱정되면 `-Wpedantic`도 단다.\n- CMake는 구성(`cmake -B build`)과 빌드(`cmake --build build`)의 2단계, gdb는 `-g`로 컴파일한 실행파일을 연다. 깊은 내용은 Part VII에서.\n- ROS 2 Humble은 우분투 22.04 기준이므로 **Docker 컨테이너**(`osrf/ros:humble-desktop`)로 격리해 준비한다. 작업물은 `-v`로 공유한 디렉터리에만 둔다.\n\n::: quiz 연습문제\n1. `g++ check20.cpp`처럼 `-std` 플래그 없이 컴파일하면 어떤 표준이 적용되는가? 그 상태에서 check20.cpp의 두 C++20 기능(concepts, designated initializer) 중 에러가 나는 것은 어느 쪽이고, 왜 다른 쪽은 통과하는가?\n2. `cmake --build build`의 출력에서 `Building CXX object`와 `Linking CXX executable`은 왜 별개의 줄로 나오는가? 각 단계에서 실패하면 어떤 종류의 에러가 나는지, [0.1](#/how-to-read)의 \"컴파일은 통과하고 링크에서 실패한다\" 예제와 연결해 설명해 보라.\n3. **[코드 작성]** check20.cpp를 복사하지 말고 직접 타이핑해서, `g++ -std=c++20 -Wall -Wextra check20.cpp -o check20 && ./check20`이 경고 없이 통과하고 `pos=1.57 half=1.6`이 나오면 성공이다. 타이핑 중 에러가 나면 지우지 말고 메시지를 한 줄씩 읽어 보라 — 그 연습이 [0.3](#/first-build)의 예습이다.\n4. **[코드 작성]** 위의 hello 프로젝트(CMakeLists.txt + main.cpp)를 직접 만들어 구성→빌드→실행까지 통과시켜라. 그다음 main.cpp의 세미콜론 하나를 일부러 지우고 `cmake --build build`를 다시 실행해, 에러 메시지에 파일명과 줄 번호가 어떻게 찍히는지 확인하라.\n:::\n\n::: answer 1번 해설\n플래그가 없으면 g++ 13은 gnu++17(GNU 확장이 섞인 C++17)로 컴파일한다. concepts는 C++17에 존재하지 않는 문법이라 `'std::floating_point' has not been declared` 에러가 난다. 반면 designated initializer는 표준 C++17에는 없지만 g++가 GNU 확장으로 받아 주기 때문에 조용히 통과한다 — `-Wpedantic`을 붙여야 경고가 된다. \"에러가 안 났다\"가 \"표준에 맞다\"를 뜻하지 않는 대표적인 사례다.\n:::\n\n**다음 절**: [0.3 첫 빌드와 에러 메시지 읽는 법](#/first-build) — 방금 깐 도구로 첫 프로그램을 빌드하고, 컴파일러가 뱉는 텍스트를 정보로 바꾸는 훈련을 시작한다.\n","first-build":"# 0.3 첫 빌드와 에러 메시지 읽는 법\n\n::: lead\n[0.2](#/toolchain-setup)에서 도구를 세웠으니 이제 첫 프로그램을 빌드한다. 그런데 이 절의 진짜 주제는 hello world가 아니다. **멀쩡한 프로그램을 일부러 네 번 깨뜨리고, 컴파일러가 뱉는 텍스트를 정보로 바꿔 읽는 훈련**이다. C++ 개발자는 하루에도 수십 번 에러 메시지를 만난다. 그 붉은 글자를 소음으로 넘기는 사람과 한 줄씩 해부해서 읽는 사람은 성장 속도가 완전히 다르다. 여기서 30분을 쓰면 앞으로 몇 년 치 디버깅 시간이 줄어든다.\n:::\n\n## 첫 프로그램\n\n에디터를 열고 아래를 **직접 타이핑한다.** 복사 버튼을 누르지 마라 — [0.1](#/how-to-read)에서 약속한 대로, 오타가 만들어 주는 에러가 오늘의 교재다.\n\n```cpp title=\"hello.cpp\"\n#include <iostream>\n\nint main() {\n    std::cout << \"hello, robot\\n\";\n    return 0;\n}\n```\n\n빌드 명령은 이것이다. 이 책 전체에서 계속 쓸 형태이니 손에 붙여 두라.\n\n```console\n$ g++ -std=c++20 -Wall -Wextra hello.cpp -o hello\n$ ./hello\nhello, robot\n```\n\n명령을 조각내면 이렇다.\n\n| 조각 | 뜻 |\n| --- | --- |\n| `g++` | GNU C++ 컴파일러 드라이버. 전처리 → 컴파일 → 링크 전 과정을 지휘한다 |\n| `-std=c++20` | 언어 표준. 이 책의 기준이다 |\n| `-Wall -Wextra` | 경고를 켠다. **항상 붙인다** — 이유는 아래 '경고는 공짜 코드 리뷰'에서 |\n| `hello.cpp` | 입력 소스 파일 |\n| `-o hello` | 출력 실행파일 이름. 생략하면 `a.out`이라는 무성의한 이름이 된다 |\n\n첫 명령이 **아무것도 출력하지 않고** 프롬프트로 돌아왔다는 것에 주목하라. 유닉스 도구의 관례다 — 침묵이 성공이다. 컴파일러가 말을 걸어오는 순간은 문제가 있을 때뿐이고, 그래서 컴파일러의 말은 전부 읽을 가치가 있다.\n\n## 일부러 깨뜨린다\n\n이제 방금 성공한 프로그램을 체계적으로 부순다. 각 깨뜨리기는 같은 리듬으로 진행한다: **어떤 에러가 날지 먼저 예측하고 → 깨뜨리고 → 컴파일하고 → 메시지를 끝까지 읽고 → 복원한다.** 예측이 틀리는 순간이 가장 크게 배우는 순간이다.\n\n이 절의 모든 컴파일러 출력은 실측이다. (g++ 13 기준 실측. 버전에 따라 문구는 조금씩 다르다.)\n\n::: note 에러 메시지는 표준이 아니다\nC++ 표준은 \"진단 메시지를 내라\"고만 요구할 뿐 문구는 컴파일러 마음이다. 같은 실수라도 g++와 clang은 다르게 말하고, g++ 12와 13도 조금 다르다. 그래서 **문구를 외우는 게 아니라 구조를 읽는 법**을 익혀야 한다. 이 절이 그 훈련이다.\n:::\n\n### 깨뜨리기 1 — 세미콜론을 지운다\n\n`hello.cpp` 4번 줄 끝의 `;`를 지우고 다시 컴파일한다.\n\n```console\n$ g++ -std=c++20 -Wall -Wextra hello.cpp -o hello\nhello.cpp: In function 'int main()':\nhello.cpp:4:34: error: expected ';' before 'return'\n    4 |     std::cout << \"hello, robot\\n\"\n      |                                  ^\n      |                                  ;\n    5 |     return 0;\n      |     ~~~~~~\n```\n\n읽어 보자. `hello.cpp:4:34`는 **파일:줄:칸**이다 — 4번 줄 34번째 칸, 즉 문자열이 끝난 직후를 가리킨다. `^`가 그 지점을 찍고, 그 아래 `;`는 \"여기에 이걸 넣으라\"는 수정 제안이다. 그런데 메시지를 보면 `before 'return'` — 컴파일러는 5번 줄의 `return`을 언급하고 있다.\n\n왜 그런가. **세미콜론이 빠진 순간에는 컴파일러도 빠졌다는 것을 모른다.** C++에서 문장은 여러 줄에 걸칠 수 있으므로, 4번 줄이 끝나도 문장이 계속되는 중일 수 있다. 컴파일러는 다음 토큰인 `return`을 읽고 나서야 \"문장이 안 끝났는데 새 문장이 시작됐다\"는 것을 알아챈다. 그래서 에러가 보고되는 위치는 실수한 위치가 아니라 **컴파일러가 실수를 알아챈 위치**다.\n\n::: warn 에러 줄 번호는 '발견 지점'이지 '원인 지점'이 아니다\n에러가 가리키는 줄에서 문제를 못 찾겠으면 **그 줄보다 앞을 보라.** 특히 `expected ';'`, `expected '}'` 류는 거의 항상 원인이 앞 줄(또는 훨씬 위)에 있다. 헤더 파일 끝에서 세미콜론을 빠뜨리면 그 헤더를 include한 **다른 파일**의 첫 줄이 에러로 지목되기도 한다. 이 성질을 모르면 멀쩡한 줄을 30분 동안 노려보게 된다.\n:::\n\n`;`를 복원하고 컴파일이 침묵하는 것까지 확인한 뒤 다음으로 간다.\n\n### 깨뜨리기 2 — #include 를 지운다\n\n이번엔 1번 줄 `#include <iostream>`을 통째로 지운다.\n\n```console\n$ g++ -std=c++20 -Wall -Wextra hello.cpp -o hello\nhello.cpp: In function 'int main()':\nhello.cpp:2:10: error: 'cout' is not a member of 'std'\n    2 |     std::cout << \"hello, robot\\n\";\n      |          ^~~~\nhello.cpp:1:1: note: 'std::cout' is defined in header '<iostream>'; did you forget to '#include <iostream>'?\n  +++ |+#include <iostream>\n    1 | int main() {\n```\n\n`'cout' is not a member of 'std'` — `std`라는 네임스페이스에 `cout`이라는 이름이 없다는 뜻이다. `<iostream>`을 include하지 않으면 `std::cout`의 선언 자체가 이 파일에 존재하지 않으므로, 컴파일러 입장에서 그 이름은 세상에 없는 것이다. include가 왜 \"선언을 가져오는\" 행위인지는 [1.9 헤더와 컴파일 단위](#/headers)에서 해부한다.\n\n여기서 진짜 볼거리는 두 번째 덩어리, `note:`로 시작하는 부분이다. g++가 원인 진단을 넘어 **해법을 통째로 알려주고 있다** — 어느 헤더에 정의돼 있는지, 뭘 잊었는지, 심지어 `+++ |+#include <iostream>` 줄은 \"1번 줄 위에 이 줄을 추가하라\"는 패치 형식의 제안이다.\n\n::: tip note 줄까지 읽어야 절반을 읽은 것이다\n많은 초심자가 `error:` 줄만 읽고 스크롤을 멈춘다. 최신 g++와 clang은 진단의 뒷부분(`note:`)에 원인 후보, 관련 선언의 위치, 수정 제안을 붙여 준다. **답의 절반은 note에 있다.** 에러 하나를 읽을 때는 다음 `error:`가 나오기 전까지의 덩어리 전체가 한 세트다.\n:::\n\n### 깨뜨리기 3 — 이름을 틀리게 친다\n\n이번엔 새 파일이다. 센서값을 읽는 척하는 작은 프로그램을 치되, **호출부에서 함수 이름을 일부러 틀리게** 친다.\n\n```cpp title=\"sensor.cpp — 8번 줄에 오타가 있다\" {8}\n#include <iostream>\n\ndouble read_sensor() {\n    return 0.42;\n}\n\nint main() {\n    std::cout << read_senor() << \"\\n\";\n    return 0;\n}\n```\n\n```console\n$ g++ -std=c++20 -Wall -Wextra sensor.cpp -o sensor\nsensor.cpp: In function 'int main()':\nsensor.cpp:8:18: error: 'read_senor' was not declared in this scope; did you mean 'read_sensor'?\n    8 |     std::cout << read_senor() << \"\\n\";\n      |                  ^~~~~~~~~~\n      |                  read_sensor\n```\n\n`was not declared in this scope` — 이 스코프에 그런 이름이 선언된 적 없다는 뜻이고, 이어서 `did you mean 'read_sensor'?`라고 정답을 짚어 준다. 컴파일러는 현재 스코프에서 보이는 이름들과 틀린 이름 사이의 **편집 거리**(몇 글자를 고치면 같아지는가)를 재서, 충분히 가까운 후보가 있으면 제안한다. 오타 에러는 대부분 이 제안 한 줄로 끝난다. 오타를 고치고 실행하면 `0.42`가 나온다.\n\n### 깨뜨리기 4 — 정의를 지운다\n\n이제 이 절에서 가장 중요한 깨뜨리기다. `sensor.cpp`에서 `read_sensor`의 **몸체를 지우고 선언만 남긴다.**\n\n```cpp title=\"sensor.cpp — 정의가 사라졌다\" {3}\n#include <iostream>\n\ndouble read_sensor();   // 선언은 남겼다\n\nint main() {\n    std::cout << read_sensor() << \"\\n\";\n    return 0;\n}\n```\n\n```console\n$ g++ -std=c++20 -Wall -Wextra sensor.cpp -o sensor\n/usr/bin/ld: /tmp/ccmdzIpp.o: in function `main':\nsensor.cpp:(.text+0x9): undefined reference to `read_sensor()'\ncollect2: error: ld returned 1 exit status\n```\n\n출력의 생김새가 지금까지와 **완전히 다르다.** 나란히 놓고 보라.\n\n```text nolines\ncompile error:\n  hello.cpp:4:34: error: expected ';' before 'return'\n  ^^^^^^^^^^^^^^ file:line:col -- source position\n\nlinker error:\n  /usr/bin/ld: ... undefined reference to `read_sensor()'\n  ^^^^^^^^^^^ speaker is ld, not g++ -- no line number\n```\n\n첫 토큰이 소스 파일명이 아니라 `/usr/bin/ld`다. **말하고 있는 주체가 컴파일러가 아니라 링커(linker)다.** 컴파일 단계는 이미 통과했다 — 선언이 있으니 컴파일러는 \"`read_sensor`라는 함수가 어딘가에 있다\"고 믿고 호출 코드를 만들어 줬다. 그 \"어딘가\"를 실제로 찾아 연결하는 것이 링커의 일인데, 어떤 파일에도 몸체가 없으니 `undefined reference`(정의되지 않은 참조)로 실패한 것이다.\n\n줄 번호가 없는 것도 우연이 아니다. `sensor.cpp:(.text+0x9)`는 \"오브젝트 파일 코드 영역의 9바이트 지점\"이라는 뜻이다 — 링커는 소스 코드가 아니라 **컴파일이 끝난 기계어 덩어리**를 다루기 때문에, 소스의 몇 번째 줄인지 알지 못한다.\n\n`undefined reference`를 보면 \"문법이 틀렸나?\"가 아니라 **\"약속한 정의를 아무도 제공하지 않았다 — 어느 파일(라이브러리)을 빼먹었나?\"**로 읽어야 한다. 이 구분은 [1.1 컴파일 모델](#/compile-model)의 주제이고, 아래 '파일이 두 개가 되면'에서 바로 다시 만난다.\n\n::: deep collect2는 누구인가\n마지막 줄 `collect2: error: ld returned 1 exit status`의 `collect2`는 g++가 링크 단계에서 부르는 내부 래퍼 프로그램이다. 전역 객체의 생성자 호출 정보를 모으는(collect) 등의 뒤처리를 한 뒤 진짜 링커 `ld`를 실행한다. 즉 이 줄은 \"내가 시킨 ld가 실패 코드 1을 돌려줬다\"는 보고이고, 진짜 정보는 그 위의 `undefined reference` 줄에 있다. `collect2` 줄 자체에는 원인이 없으니 시선을 위로 올려라.\n:::\n\n::: interview 컴파일 에러 vs 링커 에러\n\"컴파일은 되는데 링크가 안 되는 경우를 설명해 보라\"는 C++ 면접의 단골 첫 질문이다. 모범 답변의 뼈대: ① 컴파일러는 번역 단위 하나씩 처리하며 **선언만 있으면** 호출 코드를 생성할 수 있다. ② 링커는 모든 오브젝트 파일과 라이브러리를 모아 **정의를 실제로 연결**하는 단계이고, 정의가 없으면 `undefined reference`, 정의가 여러 개면 multiple definition으로 실패한다. ③ 그래서 라이브러리를 링크 목록에서 빠뜨린 것이 전형적 원인이다. 여기에 [1.10 링크리지](#/linkage)의 ODR까지 얹어 말하면 상급이다.\n:::\n\n## 에러 메시지 해부학\n\n네 번의 깨뜨리기에서 본 것을 일반 형식으로 정리한다. g++ 진단 한 덩어리의 구조는 이렇다.\n\n```text nolines\nfile:line:col: kind: message      <- where / how bad / what\n   NN | source line               <- the line, quoted\n      |      ^~~~~~               <- caret + underline: exact span\n      |      fix                  <- (optional) suggested fix\n```\n\n`kind` 자리에는 세 종류가 온다. 셋의 무게가 다르다.\n\n| 종류 | 뜻 | 빌드 |\n| --- | --- | --- |\n| `error` | 규칙 위반. 코드를 만들 수 없다 | 실패한다 |\n| `warning` | 합법이지만 수상하다. 버그일 확률이 높은 패턴 | **통과한다** |\n| `note` | 에러/경고에 붙는 부가 정보 — 원인 위치, 수정 제안 | 해당 없음 |\n\n`note`는 독립적인 문제가 아니라 직전 `error`나 `warning`의 각주다. \"에러가 몇 개 났나\"를 셀 때 note는 세지 않는다.\n\n### 연쇄 에러: 첫 에러만 고치고 재컴파일하라\n\n에러가 화면을 가득 채우면 초심자는 \"내가 뭘 얼마나 잘못했길래\"라고 얼어붙는다. 실측으로 확인해 보자. `<vector>` include 하나를 빠뜨린 파일이다.\n\n```cpp title=\"ids.cpp — 빠진 것은 #include <vector> 하나다\"\n#include <iostream>\n\nint main() {\n    std::vector<int> ids = {1, 2, 3};\n    ids.push_back(4);\n    for (int id : ids) {\n        std::cout << id << \"\\n\";\n    }\n    return 0;\n}\n```\n\n```console\n$ g++ -std=c++20 -Wall -Wextra ids.cpp -o ids\nids.cpp: In function 'int main()':\nids.cpp:4:10: error: 'vector' is not a member of 'std'\n    4 |     std::vector<int> ids = {1, 2, 3};\n      |          ^~~~~~\nids.cpp:2:1: note: 'std::vector' is defined in header '<vector>'; did you forget to '#include <vector>'?\n    1 | #include <iostream>\n  +++ |+#include <vector>\n    2 |\nids.cpp:4:17: error: expected primary-expression before 'int'\n    4 |     std::vector<int> ids = {1, 2, 3};\n      |                 ^~~\nids.cpp:5:5: error: 'ids' was not declared in this scope\n    5 |     ids.push_back(4);\n      |     ^~~\n```\n\n실수는 하나인데 에러는 세 개다. 도미노다. ① `std::vector`라는 이름이 없다(진짜 원인). ② 그러면 컴파일러는 `vector<int>`를 타입으로 읽지 못하고 `vector < int`라는 비교식으로 해석을 시도하다 실패한다. ③ 그 결과 선언문 전체가 무효가 되어 변수 `ids` 자체가 존재하지 않게 되고, 다음 줄부터 `ids`를 쓰는 곳마다 에러가 난다.\n\n②와 ③은 ①이 만든 유령이다. 고치려 들면 안 되는 에러다. 그래서 원칙은 하나다.\n\n::: tip 첫 에러만 고치고, 재컴파일하라\n컴파일러 출력에서 **첫 번째 `error:`** 를 찾아 그것만 고치고 다시 컴파일한다. 나머지 에러의 대부분은 첫 에러가 파생시킨 유령이라 저절로 사라진다. 에러 50개가 떠도 실제 실수는 한두 개인 경우가 흔하다. 출력이 길어 첫 에러가 스크롤 위로 사라지면 `g++ ... 2>&1 | head -30`으로 앞부분만 잘라 보라. 템플릿이 얽히면 에러 하나가 수백 줄이 되는데, 그 해독법은 [4.3 템플릿 인스턴스화의 실체](#/template-mechanics)에서 따로 다룬다.\n:::\n\n::: note colcon 로그도 결국 같은 형식이다\n나중에 ROS 2 패키지를 `colcon build`로 빌드하면 수십 개 패키지의 로그가 쏟아진다. 겁먹을 것 없다 — colcon은 각 패키지 안에서 CMake를 돌리고, CMake는 결국 g++를 돌린다. 실패한 패키지의 로그를 열면 그 안에 있는 것은 **오늘 배운 `파일:줄:칸: error:` 형식 그대로**다. 첫 에러를 찾아 파일:줄로 이동하는 오늘의 훈련이 [10.10 ament, colcon, 패키지 구조](#/ament-colcon)에서 그대로 통한다.\n:::\n\n## 경고는 공짜 코드 리뷰\n\n이번엔 에러가 아니라 경고다. 아래 프로그램은 **문법적으로 완전히 합법**이고, 컴파일도 실행도 된다.\n\n```cpp title=\"warn.cpp — 합법이지만 수상한 코드\"\n#include <iostream>\n#include <vector>\n\nint main() {\n    int retry_count = 3;\n    std::vector<double> joints = {0.1, 0.2, 0.3};\n    for (int i = 0; i < joints.size(); ++i) {\n        std::cout << joints[i] << \"\\n\";\n    }\n    return 0;\n}\n```\n\n경고 플래그 없이 컴파일하면 컴파일러는 침묵한다.\n\n```console\n$ g++ -std=c++20 warn.cpp -o warn\n$ ./warn\n0.1\n0.2\n0.3\n```\n\n`-Wall -Wextra`를 붙이면 같은 코드에서 이런 말이 나온다.\n\n```console\n$ g++ -std=c++20 -Wall -Wextra warn.cpp -o warn\nwarn.cpp: In function 'int main()':\nwarn.cpp:7:23: warning: comparison of integer expressions of different signedness: 'int' and 'std::vector<double>::size_type' {aka 'long unsigned int'} [-Wsign-compare]\n    7 |     for (int i = 0; i < joints.size(); ++i) {\n      |                     ~~^~~~~~~~~~~~~~~\nwarn.cpp:5:9: warning: unused variable 'retry_count' [-Wunused-variable]\n    5 |     int retry_count = 3;\n      |         ^~~~~~~~~~~\n```\n\n두 경고를 읽어 보자. 끝의 대괄호(`[-Wsign-compare]`, `[-Wunused-variable]`)는 이 경고를 켠 플래그 이름이다 — 경고의 종류를 검색하거나 개별 제어할 때 쓰는 정확한 이름이 여기 있다.\n\n**`-Wunused-variable`**: `retry_count`는 선언만 되고 한 번도 쓰이지 않았다. 무해해 보이지만, 실전에서 이 경고는 \"쓰려던 변수 대신 다른 변수를 썼다\"거나 \"리팩터링하다 로직을 지웠다\"는 신호인 경우가 많다. 죽은 코드는 읽는 사람을 속인다.\n\n**`-Wsign-compare`**: `i`는 부호 있는 `int`인데 `joints.size()`는 부호 없는 정수(`size_type`)다. 부호가 다른 두 정수를 비교하면 C++은 조용히 한쪽을 변환하는데, 이 변환이 음수를 거대한 양수로 바꿔 버릴 수 있다. 왜 그런 일이 생기는지는 [1.2 타입 시스템](#/types)에서 정수 표현을 다루며 파헤친다.\n\n::: danger 부호 없는 정수 역순 루프 — 진짜 사고가 나는 지점\nsign-compare 계열의 실수가 실제로 터지는 전형은 역순 루프다. 아래는 조각 코드다.\n\n```cpp\n// ❌ i 는 unsigned: 0에서 --i 를 하면 음수가 아니라 거대한 양수로 감긴다\nfor (std::size_t i = joints.size() - 1; i >= 0; --i) { /* ... */ }\n```\n\n`i >= 0`은 부호 없는 타입에서 **항상 참**이므로 루프가 끝나지 않고, `i`가 0 아래로 감기는 순간 배열 밖을 읽는다. 컨테이너가 비어 있으면 `size() - 1`부터 이미 거대한 양수다. 이런 코드가 로봇 관절 배열을 도는 제어 코드에 들어가면 세그폴트로 끝나면 운이 좋은 것이다. `-Wall -Wextra`는 이 계열의 실수 상당수를 커밋 전에 잡아 준다.\n:::\n\n경고의 무서운 점은 **빌드가 통과한다**는 것이다. 에러는 무시할 수 없지만 경고는 무시할 수 있고, 무시하다 보면 쌓이고, 쌓이면 아무도 안 읽는다. 그 더미 속에 진짜 버그의 예고가 묻힌다. 그래서 이 책의 기준은 명확하다. **이 책의 모든 코드는 `-Wall -Wextra`에서 경고 0개다.** 당신의 코드도 그래야 한다. 경고는 컴파일러가 무료로 해 주는 코드 리뷰이고, 리뷰를 무시하는 습관은 나중에 고치기 어렵다.\n\n::: hist -Wall은 왜 기본값이 아닌가\n`-Wall`은 \"all warnings\"라는 이름과 달리 전부를 켜지 않는다. 이 이름이 붙은 뒤 수십 년간 새 경고가 계속 추가됐는데, 기존 코드베이스의 빌드 로그를 갑자기 경고로 뒤덮지 않으려고 상당수를 `-Wall` 밖에 뒀다. 그렇게 밀려난 유용한 경고들을 모은 것이 `-Wextra`(옛 이름은 그냥 `-W`)다. 기본값이 침묵인 것도 같은 이유다 — g++는 반세기 전 C 코드도 컴파일해야 하는 도구라서, 엄격함은 옵트인이다. 새로 시작하는 코드가 `-Wall -Wextra`를 안 켤 이유는 없다.\n:::\n\n## 파일이 두 개가 되면\n\n실전 프로젝트는 파일 하나가 아니다. 함수를 다른 파일로 분리하는 최소 사례를 만들어 보자.\n\n```cpp title=\"add.cpp\"\nint add(int a, int b) {\n    return a + b;\n}\n```\n\n```cpp title=\"main.cpp\"\n#include <iostream>\n\nint add(int a, int b);   // add.cpp 에 정의가 있다고 약속한다\n\nint main() {\n    std::cout << add(2, 3) << \"\\n\";\n    return 0;\n}\n```\n\n`main.cpp` 3번 줄의 선언은 **약속**이다. \"이 서명의 함수가 어딘가에 정의돼 있으니, 일단 호출 코드를 만들어 달라.\" 컴파일러는 약속을 믿고, 약속의 이행 여부는 링커가 검사한다. 두 파일을 같이 주면 링커가 `add`의 정의를 `add.cpp` 쪽에서 찾아 연결한다.\n\n```console\n$ g++ -std=c++20 -Wall -Wextra main.cpp add.cpp -o calc\n$ ./calc\n5\n```\n\n`main.cpp`만 주면? 예측해 보라. 깨뜨리기 4에서 본 그 에러다.\n\n```console\n$ g++ -std=c++20 -Wall -Wextra main.cpp -o calc\n/usr/bin/ld: /tmp/cc9ATveL.o: in function `main':\nmain.cpp:(.text+0x13): undefined reference to `add(int, int)'\ncollect2: error: ld returned 1 exit status\n```\n\n이제 이 메시지가 읽힌다. 문법 문제가 아니다 — `add`의 정의가 든 파일을 링크 목록에서 빠뜨렸다는 뜻이고, 처방은 `add.cpp`를 명령에 추가하는 것이다.\n\n한 걸음 더. 컴파일과 링크를 **명시적으로 분리**할 수도 있다. `-c`는 \"컴파일만 하고 링크는 하지 마라\"는 뜻이고, 결과물은 `.o`(오브젝트 파일)다.\n\n```console\n$ g++ -std=c++20 -Wall -Wextra -c main.cpp\n$ g++ -std=c++20 -Wall -Wextra -c add.cpp\n$ g++ main.o add.o -o calc\n$ ./calc\n5\n```\n\n```text nolines\nmain.cpp --(compile -c)--> main.o --+\n                                    +--(link)--> calc\nadd.cpp  --(compile -c)--> add.o ---+\n```\n\n왜 이런 번거로운 짓을 하는가. **바뀐 파일만 다시 컴파일하기 위해서다.** `main.cpp`만 고쳤다면 `add.o`는 그대로 두고 `main.cpp`만 재컴파일한 뒤 링크만 다시 하면 된다. 파일이 수백 개인 프로젝트에서 이 차이는 \"3초 vs 20분\"이다. 각 단계에서 정확히 무슨 일이 일어나는지 — 전처리가 무엇을 지우고, 오브젝트 파일 안에 무엇이 들어 있고, 링커가 심볼을 어떻게 맞춰 보는지 — 는 [1.1 컴파일 모델](#/compile-model)에서 전부 연다.\n\n## CMake: 지금은 3줄만 외운다\n\n파일이 늘수록 `g++` 명령은 길어지고, \"바뀐 것만 다시 컴파일\"을 손으로 관리하는 것은 불가능해진다. 그 일을 대신하는 표준 도구가 CMake다. 최소 예제는 3줄이다.\n\n```cmake title=\"CMakeLists.txt\"\ncmake_minimum_required(VERSION 3.16)\nproject(hello)\nadd_executable(hello hello.cpp)\n```\n\n`hello.cpp`와 같은 디렉터리에 이 파일을 만들고, 두 명령을 실행한다.\n\n```console\n$ cmake -B build\n-- The CXX compiler identification is GNU 13.3.0\n...\n-- Configuring done (0.4s)\n-- Generating done (0.0s)\n-- Build files have been written to: .../build\n$ cmake --build build\n[ 50%] Building CXX object CMakeFiles/hello.dir/hello.cpp.o\n[100%] Linking CXX executable hello\n[100%] Built target hello\n$ ./build/hello\nhello, robot\n```\n\n출력에서 익숙한 단어를 찾아보라 — `Building CXX object`(컴파일, `.o` 생성)와 `Linking CXX executable`(링크). CMake는 마법이 아니라 방금 손으로 한 `-c`와 링크를 대신 해 주는 관리자다. 빌드 산출물은 전부 `build/` 디렉터리 안에 격리되므로 소스 트리가 더러워지지 않고, 다시 빌드하면 바뀐 파일만 컴파일된다.\n\n`cmake -B build`(구성)와 `cmake --build build`(빌드) 두 명령은 **지금은 이유를 묻지 말고 외워서 쓴다.** 타겟이 무엇이고 프로퍼티가 어떻게 전파되는지는 [7.1 CMake 기초](#/cmake-basics)에서 제대로 이해한다. ROS 2의 빌드 도구 colcon도 결국 패키지마다 이 CMake를 돌려 주는 바깥 껍데기다.\n\n## 요약\n\n- 빌드 명령의 기준형은 `g++ -std=c++20 -Wall -Wextra 파일.cpp -o 이름`이다. 침묵이 성공이다.\n- 에러 위치 `파일:줄:칸`은 **발견 지점**이다. 원인은 그보다 앞에 있을 수 있다 — 특히 `expected ';'` 류.\n- 진단은 `error`(빌드 실패) / `warning`(통과하지만 수상) / `note`(각주: 원인·수정 제안)의 세 종류다. note까지가 한 세트다.\n- 연쇄 에러는 도미노다. **첫 에러만 고치고 재컴파일하라.**\n- `undefined reference`는 링커(`ld`) 에러다. 문법이 아니라 \"정의가 든 파일·라이브러리를 빠뜨렸다\"로 읽는다.\n- 경고는 공짜 코드 리뷰다. 이 책의 모든 코드는 `-Wall -Wextra` 경고 0개가 기준이고, 당신 코드도 그래야 한다.\n- CMake 최소형: 3줄 `CMakeLists.txt` + `cmake -B build` + `cmake --build build`. 이해는 7.1에서.\n\n::: quiz 연습문제\n1번과 2번은 에러 메시지를 읽는 문제, 3번은 개념 문제, 4번과 5번은 **직접 깨뜨려 보는 실습**이다. 실습의 성공 기준은 \"네 컴퓨터에서 같은 종류의 에러가 나는가\"다.\n\n1. 아래 실측 출력을 보라. 컴파일러는 6번 줄을 가리키지만 6번 줄은 멀쩡하다. 원인은 어디에 있고, 무엇인가?\n\n   ```console\n   $ g++ -std=c++20 -Wall -Wextra greet.cpp -o greet\n   greet.cpp: In function 'int main()':\n   greet.cpp:6:5: error: expected ',' or ';' before 'std'\n       6 |     std::cout << name << \"\\n\";\n         |     ^~~\n   ```\n\n2. 아래 실측 출력은 어느 단계(컴파일/링크)의 실패인가? 근거가 되는 단서 두 가지를 대고, 처방을 말하라.\n\n   ```console\n   $ g++ -std=c++20 -Wall -Wextra motor.cpp -o motor\n   /usr/bin/ld: /tmp/ccaABA6D.o: in function `main':\n   motor.cpp:(.text+0xe): undefined reference to `clamp_pwm(int)'\n   collect2: error: ld returned 1 exit status\n   ```\n\n3. 컴파일러 출력에 `error` 12개가 떴다. 왜 12개를 순서대로 다 고치려 들면 안 되는가? 올바른 절차는 무엇인가?\n\n4. (실습) `hello.cpp`에서 마지막 줄의 닫는 중괄호 `}`를 지우고 컴파일하라. 어떤 에러가 나는지 예측한 뒤 실행하고, 에러에 붙은 `note:`가 무엇을 가리키는지 확인하라. 성공 기준: `expected '}'` 계열의 에러가 재현된다.\n\n5. (실습) `hello.cpp`에서 문자열의 닫는 따옴표 `\"`를 지우고 컴파일하라. 이번에는 같은 지점에 대해 `warning`과 `error`가 **둘 다** 나온다. 그다음, 이 절의 깨뜨리기 1~4를 처음부터 다시 재현하면서 각각이 컴파일 단계 에러인지 링크 단계 에러인지 소리 내어 분류하라. 성공 기준: 네 개 모두 같은 종류의 에러가 나고, 링크 에러는 하나뿐임을 확인한다.\n:::\n\n::: answer 해설\n1. 원인은 **5번 줄 끝의 세미콜론 누락**이다(`std::string name = \"hexpider\"` 뒤). 문장이 끝나지 않았음을 컴파일러는 6번 줄 첫 토큰 `std`를 보고서야 알았고, 그래서 발견 지점인 6:5가 보고됐다. `expected ';'` 류는 지목된 줄의 **앞**을 본다 — 깨뜨리기 1의 원칙 그대로다.\n2. **링크 단계**다. 단서: ① 말하는 주체가 `/usr/bin/ld`이고 마지막 줄이 `collect2: error: ld returned ...`다. ② 위치가 `파일:줄:칸`이 아니라 `(.text+0xe)` — 링커는 소스 줄을 모른다. 처방: `clamp_pwm`의 **정의**를 작성하거나, 정의가 들어 있는 `.cpp`/라이브러리를 링크 명령에 추가한다.\n3. 첫 에러가 파싱을 무너뜨리면 뒤따르는 에러 대부분은 파생된 유령이기 때문이다(`ids.cpp`에서 실수 1개가 에러 3개를 만든 것처럼). 절차: **첫 `error:` 하나만 고치고 재컴파일** — 남은 에러 수가 급감하는 것을 확인하고 반복한다.\n4. g++ 13 실측으로는 `error: expected '}' at end of input`이 나오고, `note: to match this '{'`가 **짝이 안 맞는 여는 중괄호**(`int main() {`)의 위치를 가리킨다. 중괄호 짝 에러에서 note는 \"어느 `{`가 닫히지 않았나\"를 알려주는 핵심 단서다.\n5. 따옴표 실습의 실측은 `warning: missing terminating \" character`와 같은 문구의 `error`가 연달아 나온다(전처리 시점과 컴파일 시점이 각각 문제를 보고한다). 분류: 깨뜨리기 1(세미콜론)·2(include)·3(오타)은 컴파일 단계, **깨뜨리기 4(정의 없음)만 링크 단계**다. 이 구분이 자동으로 나오면 이 절의 목표는 달성이다.\n:::\n\n이 절은 읽기만 하면 남는 게 없다. 지금 IDE 터미널에서 `hello.cpp`부터 `CMakeLists.txt`까지 전부 직접 치고, 네 번의 깨뜨리기를 전부 재현하라. 기준 명령은 `g++ -std=c++20 -Wall -Wextra hello.cpp -o hello && ./hello`다.\n\n**다음 절**: [0.4 학습 워크플로: 앱과 IDE의 병행](#/workflow) — 이 앱과 IDE를 어떻게 배치하고 어떤 리듬으로 오갈지, 복습 루틴까지 잡는다.\n","workflow":"# 0.4 학습 워크플로: 앱과 IDE의 병행\n\n::: lead\n[0.1](#/how-to-read)에서 원칙을 세웠다 — 직접 타이핑하고, 결과를 예측한 뒤 실행하고, 위젯으로 확인한다. [0.2](#/toolchain-setup)와 [0.3](#/first-build)에서 도구도 갖췄다. 이 절은 그 원칙을 **매일 반복 가능한 손 순서**로 바꾼다. 화면을 어떻게 배치하고, 절 하나를 어떤 단계로 돌고, 실습 파일을 어디에 어떤 이름으로 쌓고, 언제 무엇으로 복습하는지. 한 번 정해 두면 앞으로 100개가 넘는 절이 전부 같은 방식으로 굴러간다. 워크플로를 정하는 데 드는 시간은 오늘 30분이고, 아끼는 시간은 그 수백 배다.\n:::\n\n## 화면 배치: 읽는 창과 만드는 창\n\n이 책의 학습은 두 창 사이의 왕복이다. 읽는 창(이 앱)과 만드는 창(IDE). 왕복이 잦을수록 창 전환 비용이 학습을 갉아먹으므로, **두 창이 동시에 보이는 배치**가 기본이다.\n\n**듀얼 모니터라면** 왼쪽에 이 앱, 오른쪽에 VSCode를 놓는다. 좌우는 취향이지만 한 번 정하면 바꾸지 마라 — \"코드는 항상 오른쪽\"이 몸에 배면 시선 이동이 무의식이 된다. 터미널은 별도 창을 띄우지 말고 VSCode 통합 터미널(<kbd>Ctrl</kbd>+<kbd>`</kbd>)을 쓴다. 에디터·터미널·컴파일 에러가 한 화면에 모여야 [0.3](#/first-build)에서 훈련한 에러 읽기 루프가 빨라진다.\n\n**모니터가 하나라면** 화면을 절반으로 가른다. 윈도우는 <kbd>Win</kbd>+<kbd>←</kbd>/<kbd>→</kbd>, 우분투는 <kbd>Super</kbd>+<kbd>←</kbd>/<kbd>→</kbd>, macOS는 창 초록 버튼을 길게 눌러 타일링. 왼쪽 절반에 이 앱, 오른쪽 절반에 VSCode다.\n\n이 앱이 절반 폭에서도 깨지지 않는 것은 우연이 아니다. **절반 폭이 이 앱의 기본 사용 폭이라고 보고 설계했다.** 화면이 좁아지면 오른쪽 절내 목차가 자동으로 숨고, 본문 폭이 코드 블록 기준으로 잡혀 있다. 전체 화면으로 넓게 펴 놓고 읽는 것은 오히려 이 책이 의도한 사용법이 아니다 — 그 배치에는 IDE가 없기 때문이다.\n\n::: tip 앱 쪽 글자를 한 단계 줄여라\n절반 폭에서는 상단 오른쪽 아이콘으로 글자 크기를 한 단계 줄이는 쪽이 대개 읽기 편하다. 한 화면에 들어오는 문맥이 넓어져서 코드 블록과 그 설명 문단이 같이 보인다. 코드와 설명이 따로 스크롤되기 시작하면 이해가 끊긴다.\n:::\n\n## 절 하나를 도는 루틴\n\n이 책의 최소 학습 단위는 절이다. 절 하나를 도는 절차를 고정하라. 여섯 단계다.\n\n**① lead를 읽고 \"왜\"를 잡는다.** 모든 절은 `lead` 상자로 시작한다. 여기서 얻어야 할 것은 지식이 아니라 질문이다 — *이 절이 없으면 무엇이 안 되는가.* 질문 없이 본문에 들어가면 읽기는 스캔이 되고, 스캔한 내용은 하루를 못 간다.\n\n**② 코드가 나오면, 결과를 먼저 말한 뒤 IDE에 타이핑한다.** 본문의 코드 블록을 만나면 눈으로 넘기지 말고 멈춘다. 실행 결과를 예측해서 소리 내어 말하거나 주석으로 적는다 — \"이건 링커 에러\", \"출력은 3, 힙 할당은 두 번\". 그 다음 오른쪽 창에서 **직접 타이핑한다.** 복사 버튼은 없다고 생각하라. 이유는 [0.1](#/how-to-read)에서 말했다 — 타이핑 실수가 곧 에러 메시지 읽기 훈련이다.\n\n**③ 실행해서 예측과 대조한다.** 맞았으면 지식이 확인된 것이고, **틀렸으면 그 지점이 오늘의 수확이다.** 예측과 실제의 어긋남이 당신의 멘탈 모델에서 정확히 어디가 잘못됐는지 알려 준다. 틀린 예측을 파일 상단 주석에 남겨라 — `// 예측: 컴파일 에러 / 실제: 통과, 경고만` 한 줄이면 된다. 나중에 이 주석이 복습 자료가 된다.\n\n**④ 위젯이 있으면 앞뒤로 오가며 자기 말로 설명한다.** 재생 버튼으로 한 번 흘려 본 뒤, 스텝을 수동으로 되감아라. 임의의 스텝에서 멈추고 *\"지금 이 상태가 된 이유\"* 를 자기 말로 설명할 수 있는지 확인한다. 설명이 막히는 스텝이 바로 이해가 빈 지점이다. 그 스텝 앞뒤를 오가며 무엇이 변했는지 본다.\n\n**⑤ quiz를 푼다.** 개념 문제는 답을 보기 전에 손으로 쓴다. 실습형 문제의 성공 기준은 답안 확인이 아니라 **당신의 컴퓨터에서 컴파일이 통과하고 새니타이저가 조용한 것**이다. Part II부터는 이런 문제가 절마다 섞인다.\n\n**⑥ '완료로 표시'는 다시 설명할 수 있을 때만 누른다.** 절 맨 아래 완료 버튼은 \"읽었음\"이 아니라 \"설명할 수 있음\"의 표시다. 기준은 하나 — *이 절의 핵심을 코드 없이 말로 재구성할 수 있는가.* 안 되면 체크하지 말고 넘어가라. [0.1](#/how-to-read)의 원칙 3대로, 비워 둔 체크는 부끄러운 게 아니라 정확한 상태 기록이다.\n\n::: warn \"아는 내용\"이 가장 위험하다\n②를 건너뛰게 만드는 것은 어려운 절이 아니라 쉬워 보이는 절이다. \"이 정도는 안다\"며 눈으로만 읽은 절에서 예측 실패가 가장 많이 나온다. 특히 다른 언어 경험이 있다면 — `=` 가 복사라는 것, 정수 나눗셈, 암묵 변환 — C++은 당신의 직관이 다른 언어에서 왔다는 사실을 노린다. 쉬워 보일수록 예측을 명시적으로 하라.\n:::\n\n::: tip 한 세션에 한 절이면 충분하다\n이 책의 절은 15~30분 분량으로 잡혀 있지만, 위 루틴을 다 돌면 실제로는 40~60분이 든다. 그게 정상이다. 하루에 세 절을 눈으로 읽는 것보다 한 절을 여섯 단계로 도는 쪽이 일주일 뒤에 남는 양이 많다. 진도 그래프의 속도가 아니라 ⑥의 기준을 지키는 것이 진짜 진도다.\n:::\n\n## 실습 디렉터리 규율: ~/cpp-lab\n\n②와 ③에서 타이핑한 코드를 아무 데나 버리지 마라. **연습장 디렉터리 하나를 파고, 절마다 파일 하나씩 쌓는다.**\n\n```console\n$ mkdir ~/cpp-lab && cd ~/cpp-lab\n$ git init\n```\n\n파일 이름은 `ch<장>-<절>-<키워드>.cpp` 로 통일한다. 몇 주 뒤에는 이런 모양이 된다.\n\n```text nolines\n~/cpp-lab/\n├── ch1-1-linker-error.cpp      <- 1.1 링커 에러 재현\n├── ch1-2-overflow.cpp          <- 1.2 정수 오버플로\n├── ch2-1-stack-frame.cpp       <- 2.1 스택 프레임 관찰\n├── ch2-7-move.cpp              <- 2.7 이동 시맨틱\n├── ch2-7-quiz.cpp              <- 2.7 연습문제 답안\n└── notes.md                    <- 절 번호별 한 줄 메모\n```\n\n왜 이렇게 하는가. 첫째, **지난 실습이 곧 나만의 예제 사전이 된다.** \"이동 시맨틱 예제가 뭐였지\" 싶을 때 남의 블로그가 아니라 `ch2-7-move.cpp` 를 연다. 거기엔 당신이 친 코드, 당신이 틀린 예측 주석, 당신이 고친 흔적이 있다 — 검색으로 나오는 어떤 예제보다 회수율이 높다. 둘째, 파일명에 절 번호가 박혀 있으므로 코드에서 책으로, 책에서 코드로 양방향 검색이 된다. `ls ch2-*` 한 줄이 Part II 복습 목록이다.\n\n컴파일 명령은 매번 치지 말고 셸 알리아스로 박아 둔다.\n\n```bash\n# ~/.bashrc 에 추가 — 이 책의 표준 컴파일 명령\nalias cpx='g++ -std=c++20 -Wall -Wextra -fsanitize=address,undefined'\n```\n\n이후 실습은 `cpx ch2-7-move.cpp && ./a.out` 으로 끝난다. 새니타이저를 기본 포함시키는 이유는 [2.11](#/ub-sanitizers)에서 다루지만, 지금은 \"켜 두면 미래의 버그가 지금 잡힌다\"만 알면 된다.\n\n::: tip 커밋이 복습 기록이 된다\n절 하나를 끝낼 때마다 `git add -A && git commit -m \"ch2-7 move semantics\"` 한 줄. 이러면 `git log --oneline` 이 학습 일지가 되고, 몇 달 뒤 `git diff` 로 초기 코드를 열어 보면 자신의 변화가 보인다. 원격에 올릴 필요도 없다 — 로컬 저장소로 충분하다.\n:::\n\n## 복습 루틴: 세 개의 고리\n\n복습을 \"시간 나면 하는 것\"으로 두면 안 한다. 기존 루틴에 붙어 있는 세 개의 고리로 고정하라.\n\n**고리 1 — 다음 절에 들어가기 전, 직전 절의 quiz를 다시 푼다.** 5분이면 된다. 어제의 답을 기억해서 맞히는 것은 의미가 없고, **풀이 과정을 다시 만들어낼 수 있는지**가 검사 대상이다. 두 번째에도 막히는 문제는 해당 절의 완료 체크를 해제하라 — ⑥의 기준을 소급 적용하는 것이다.\n\n**고리 2 — 주말에 그 주에 읽은 절의 interview 상자만 훑는다.** 왼쪽 목차에서 이번 주에 체크한 절들을 열고 🎤 상자만 골라 읽는다. interview 상자는 그 절의 핵심을 \"설명하라\"는 형태로 압축해 놓은 것이라, 답변 뼈대를 소리 내어 말해 보는 것만으로 ⑥의 기준 검사가 된다. 이 습관이 쌓이면 [12.4 기술면접 총정리](#/interview-cpp)에 도달했을 때 할 일이 \"정리\"가 아니라 \"확인\"이 된다.\n\n**고리 3 — 용어가 가물하면 그 자리에서 용어 사전을 연다.** 왼쪽 아래 용어 사전에 모든 용어의 한 줄 정의와 최초 등장 절이 있다. \"lvalue가 뭐였지\" 상태로 본문을 계속 읽는 것은 모래 위에 쌓는 것이다. 30초를 써서 바닥을 다지고 돌아와라.\n\n::: note 복습 도구는 이 세 가지가 전부다\n별도의 복습 화면이나 자동 알림 같은 것은 이 앱에 없다. quiz 재풀이, interview 상자, 용어 사전 — 전부 이미 본문에 있는 것을 다시 여는 방식이다. 도구가 단순한 대신 루틴을 당신이 지켜야 한다. 고리 1은 \"다음 절 열기 전\"에, 고리 2는 \"주말\"에 붙어 있으므로 별도의 의지력이 거의 안 든다.\n:::\n\n## 폰에서의 복습: EPUB\n\n이동 중까지 학습을 끌고 가고 싶다면, 이 앱을 폰 브라우저로 여는 대신 **EPUB로 내보내서 폰 기본 e리더로 읽는다.** 이 앱은 PC 전용이다 — 폰에는 IDE가 없으므로 여섯 단계 루틴의 절반이 불가능하고, 그렇다면 폰에서 할 일은 순수 텍스트 복습뿐이기 때문이다.\n\n```console\n$ cd Cpp_for_ROS\n$ python tools/export_epub.py\ndist/ 에 EPUB 파일이 생성된다\n```\n\n생성된 파일을 폰으로 옮겨(이메일, 클라우드 드라이브, USB 아무거나) 기본 e리더로 연다 — iOS는 Apple Books, 안드로이드는 Play Books가 EPUB를 바로 읽는다.\n\nEPUB에는 위젯이 없다. 대신 이 책의 본문은 **위젯 없이도 개념이 전달되도록** 쓰여 있다 — 위젯은 이해를 새기는 도구이지 본문의 구멍을 메우는 도구가 아니라는 것이 이 책의 집필 원칙이다. 그래서 EPUB 복습은 \"위젯에서 봤던 그 상태 변화를 글만 읽고 머릿속에서 재생할 수 있는가\"를 검사하는, 꽤 좋은 시험이기도 하다.\n\n::: warn 진도의 기준점은 PC 앱 하나다\ne리더의 읽은 위치, 북마크는 EPUB 파일 안의 참고 기록일 뿐이다. 완료 체크와 진도 그래프는 PC 앱의 브라우저 `localStorage` 에만 있다 — [0.1](#/how-to-read)에서 말한 대로 **이 PC의 이 브라우저가 유일한 기준점**이다. 폰에서 두 절을 읽었어도 완료 판정(⑥)은 PC로 돌아와 IDE 실습까지 마친 뒤에 하라. 본문을 다시 내보냈다면 옛 EPUB는 지우고 새 파일로 교체한다.\n:::\n\n## Hexpider 프로젝트와의 병행\n\n이 책의 종착지는 책이 아니라 로봇이다. 실전 프로젝트 — 6족 보행 로봇 Hexpider — 와 이 책을 어떻게 맞물릴 것인가.\n\n**Part I~II를 도는 동안은 책에 집중하라.** 이 시기에 프로젝트 코드를 열면 모든 줄이 물음표라 병행의 효율이 안 나온다. 단, 구경은 다르다 — `ros2_control` 의 `hardware_interface` 소스를 일주일에 한 번 열어서 \"여전히 안 읽히는가\"를 확인하는 것은 좋은 진도 측정이다.\n\n**Part II와 VI를 마치면 첫 번째 문이 열린다.** `hardware_interface` 코드의 골격 — 왜 `unique_ptr` 로 하드웨어를 소유하는지, 왜 `read()`/`write()` 루프가 별도 스레드에서 도는지, 왜 그 루프 안에서 할당을 피하는지 — 가 읽히기 시작한다. [2.1 메모리 모델](#/memory-model)에서 시작한 소유권 이야기와 Part VI의 스레드 이야기가 전부 그 코드 안에 있다.\n\n**Part IX~X는 병행이 기본이다.** 역기구학 절을 읽은 주에 헥사포드 다리 IK를 실제로 구현하고, executor 절을 읽은 주에 노드의 콜백 구조를 손보는 식으로, **읽는 것과 만드는 것의 간격을 일주일 이내로** 유지하라. 이 구간은 책이 프로젝트의 해설서 역할을 하도록 설계되어 있어서, 순차(책 다 읽고 프로젝트 시작)보다 병행이 압도적으로 효율이 좋다.\n\n어느 파트가 Hexpider의 어느 단계에 대응하는지 전체 지도는 [12.5 Hexpider 로드맵 매핑](#/hexpider-map)에 있다. 미리 한 번 훑어 두면 \"지금 배우는 게 어디에 쓰이는가\"라는 질문에 항상 답을 갖고 읽게 된다.\n\n## 요약\n\n- 두 창이 동시에 보이는 배치가 기본이다. 듀얼 모니터면 앱/IDE를 좌우로, 하나면 절반 분할 — 이 앱은 절반 폭을 기준으로 설계됐다.\n- 절 하나의 루틴: **lead로 \"왜\" 잡기 → 예측 말하고 타이핑 → 실행해 대조(틀리면 수확) → 위젯을 오가며 자기 말로 설명 → quiz(실습형은 컴파일 통과가 기준) → 다시 설명할 수 있을 때만 완료 체크.**\n- 실습은 `~/cpp-lab/` 에 `ch2-7-move.cpp` 식으로 쌓는다. 지난 실습이 나만의 예제 사전이 된다.\n- 복습은 세 고리: 다음 절 전에 직전 quiz 재풀이, 주말에 interview 상자 훑기, 용어가 가물하면 즉시 용어 사전.\n- 이동 중 복습은 `python tools/export_epub.py` 로 만든 EPUB + 폰 기본 e리더. 진도의 기준점은 PC 앱 하나다.\n- Hexpider 병행: Part II·VI를 마치면 `hardware_interface` 가 읽히기 시작하고, Part IX~X는 실전 구현과 일주일 이내 간격의 병행이 가장 효율적이다.\n\n::: quiz 연습문제\n1. **[실습]** `~/cpp-lab/` 을 만들고 `git init` 하라. 첫 파일 `ch0-4-hello.cpp` 를 직접 타이핑해서 만들고(내용은 [0.3](#/first-build)의 hello world면 된다), 알리아스 `cpx` 를 등록한 뒤 `cpx ch0-4-hello.cpp && ./a.out` 이 통과하면 성공이다.\n2. 여섯 단계 루틴 중 ②(예측 후 타이핑)를 생략하면 ③(대조)이 왜 같이 무너지는지 한 문장으로 설명하라.\n3. 당신의 일주일을 기준으로 복습 세 고리를 배치해 보라 — 고리 1은 언제, 고리 2는 어느 요일 어느 시간대인가. 구체적인 요일·시간이 없는 계획은 계획이 아니다.\n4. [1.1 컴파일 모델](#/compile-model)을 이 절의 루틴대로 돌 때, ②에서 예측을 적을 코드가 이미 하나 있다 — [0.1](#/how-to-read)의 \"이 코드는 컴파일될까?\" 예제다. 지금 답을 보지 않은 상태라면, 예측을 `notes.md` 에 먼저 적어 두라.\n:::\n\n::: answer 2번 해설\n③의 학습 효과는 예측과 실제의 **차이**에서 나온다. ②를 생략하면 비교할 예측이 없으므로 실행 결과는 그냥 \"그렇구나\"로 흘러간다 — 어긋남이 없으면 멘탈 모델의 어디가 틀렸는지 알 수 없고, 고칠 것도 없다. 실행은 했지만 학습은 일어나지 않은 상태가 된다.\n:::\n\n**다음 절**: [1.1 컴파일 모델: 전처리 → 컴파일 → 링크](#/compile-model) — 소스 파일이 실행파일이 되기까지 컴파일러와 링커가 실제로 하는 일. 여기서부터 여섯 단계 루틴이 시작된다.\n"},"glossary":[{"term":"designated initializer (지정 초기화)","def":"구조체 멤버를 이름으로 지정해 초기화하는 C++20 문법 — { .position = 1.57 } 형태.","chapter":"toolchain-setup"},{"term":"concepts (콘셉트)","def":"템플릿 인자가 만족해야 할 제약을 타입에 새기는 C++20 기능. 4.5절에서 본격적으로 다룬다.","chapter":"toolchain-setup"},{"term":"build-essential","def":"gcc, g++, make, C 표준 라이브러리 헤더를 묶은 우분투 메타패키지. C++ 빌드 환경의 최소 단위.","chapter":"toolchain-setup"},{"term":"GNU 확장","def":"표준 C++가 아니지만 g++가 추가로 받아 주는 문법. 기본 모드(gnu++17 등)에서 조용히 통과해 이식성 문제를 만든다.","chapter":"toolchain-setup"},{"term":"구성 (configure)","def":"CMake의 1단계 — 컴파일러를 찾고 빌드 파일을 생성한다. 실제 컴파일은 2단계인 빌드(cmake --build)에서 일어난다.","chapter":"toolchain-setup"},{"term":"디버그 정보 (-g)","def":"실행파일에 소스 줄 번호와 변수 이름을 담는 컴파일 옵션. gdb로 열려면 필요하다.","chapter":"toolchain-setup"},{"term":"컴파일러 드라이버 (compiler driver)","def":"전처리·컴파일·링크 전 과정을 지휘하는 실행 파일(g++).","chapter":"first-build"},{"term":"undefined reference","def":"선언으로 약속된 정의를 링커가 어떤 오브젝트 파일에서도 찾지 못했다는 링크 단계 에러.","chapter":"first-build"},{"term":"오브젝트 파일 (object file, .o)","def":"-c 옵션으로 컴파일만 마친, 링크 전 단계의 기계어 산출물.","chapter":"first-build"},{"term":"분리 컴파일 (separate compilation)","def":"소스 파일별로 .o를 만들어 두고 바뀐 파일만 재컴파일한 뒤 링크만 다시 하는 방식.","chapter":"first-build"},{"term":"진단 메시지 (diagnostic)","def":"컴파일러가 내는 error(빌드 실패)/warning(통과하지만 수상)/note(각주) 세 종류의 출력.","chapter":"first-build"},{"term":"연쇄 에러 (cascading errors)","def":"첫 에러가 파싱을 무너뜨려 파생시키는 유령 에러들 — 첫 에러만 고치고 재컴파일한다.","chapter":"first-build"},{"term":"수정 제안 (fix-it)","def":"진단 메시지에 붙는 패치 형식의 고침 제안(예: +++ |+#include <iostream>).","chapter":"first-build"}]};
